/**
 * @pie/platform - Cross-platform abstraction layer for Pie Agent Framework
 *
 * Supports both Node.js and PuerTS (Unity) environments.
 *
 * Usage:
 * ```typescript
 * import { getFileSystem, detectPlatform } from "@pie/platform";
 *
 * const fs = getFileSystem();
 * const content = await fs.readFile("path/to/file.txt");
 *
 * const platform = detectPlatform(); // "node" | "puerts" | "unknown"
 * ```
 */

