import type { FileSystem, HttpClient, PlatformContext } from "./types.js";
import { detectPlatform, getCapabilities } from "./detector.js";
import { NodeFileSystem } from "./node-fs.js";
import { PuerTSFileSystem } from "./puerts-fs.js";
import { NodeHttpClient, PuerTSHttpClient } from "./http.js";

// Singleton instances
let fileSystemInstance: FileSystem | null = null;
let httpClientInstance: HttpClient | null = null;
let platformContextInstance: PlatformContext | null = null;

/**
 * Get the appropriate FileSystem implementation for the current platform
 * Returns a cached singleton instance
 */
export function getFileSystem(): FileSystem {
  if (!fileSystemInstance) {
    const platform = detectPlatform();
    switch (platform) {
      case "puerts":
        fileSystemInstance = new PuerTSFileSystem();
        break;
      case "node":
      default:
        fileSystemInstance = new NodeFileSystem();
        break;
    }
  }
  return fileSystemInstance;
}

/**
 * Get the appropriate HttpClient implementation for the current platform
 * Returns a cached singleton instance
 */
export function getHttpClient(): HttpClient {
  if (!httpClientInstance) {
    const platform = detectPlatform();
    // PuerTS with Node.js backend can use NodeHttpClient
    // Only use PuerTSHttpClient (UnityWebRequest) if Node.js modules are not available
    switch (platform) {
      case "puerts":
        // Check if Node.js https module is available (PuerTS Node backend)
        try {
          const testRequire = (globalThis as any).require || require;
          if (testRequire("https")) {
            httpClientInstance = new NodeHttpClient();
          } else {
            httpClientInstance = new PuerTSHttpClient();
          }
        } catch {
          httpClientInstance = new PuerTSHttpClient();
        }
        break;
      case "node":
      default:
        httpClientInstance = new NodeHttpClient();
        break;
    }
  }
  return httpClientInstance;
}

/**
 * Get the full platform context
 */
export function getPlatformContext(): PlatformContext {
  if (!platformContextInstance) {
    const type = detectPlatform();
    platformContextInstance = {
      type,
      fileSystem: getFileSystem(),
      httpClient: getHttpClient(),
      capabilities: getCapabilities(type),
    };
  }
  return platformContextInstance;
}

/**
 * Reset cached instances (mainly for testing)
 */
export function resetPlatformCache(): void {
  fileSystemInstance = null;
  httpClientInstance = null;
  platformContextInstance = null;
}

/**
 * Override the HTTP client with a custom implementation.
 * Useful for injecting a Unity-specific HTTP client before the Agent starts.
 */
export function setHttpClient(client: HttpClient): void {
  httpClientInstance = client;
  platformContextInstance = null; // reset context so it picks up new client
}

/**
 * Convenience function to check if running in a specific platform
 */
export function isPlatform(platform: "node" | "puerts"): boolean {
  return detectPlatform() === platform;
}
