declare const CS: any;

export interface LoadedSkill {
  name: string;
  description: string;
  source: "builtin" | "project";
  content?: string;
  path?: string;
}

const BUILTIN_SKILLS: LoadedSkill[] = [];

function normalizePath(path: string): string {
  return String(path ?? "").replace(/\\/g, "/");
}

function parseBridgePathArray(methodName: "getSkillSearchPathsJson" | "getExtensionSearchPathsJson"): string[] {
  const raw = (globalThis as any).pieBridge?.[methodName]?.();
  if (typeof raw !== "string" || raw.trim().length === 0) {
    return [];
  }

  try {
    const parsed = JSON.parse(raw);
    return Array.isArray(parsed)
      ? parsed.map((entry) => normalizePath(String(entry ?? ""))).filter((entry) => entry.length > 0)
      : [];
  } catch {
    return [];
  }
}

export function getSkillSearchPaths(_projectRoot: string): string[] {
  return parseBridgePathArray("getSkillSearchPathsJson");
}

export function getExtensionSearchPaths(_projectRoot: string): string[] {
  return parseBridgePathArray("getExtensionSearchPathsJson");
}

function parseSkillDescription(content: string): string {
  const frontmatterMatch = content.match(/^---\n[\s\S]*?description:\s*["']?(.+?)["']?(?:\n|$)/m);
  if (frontmatterMatch) return frontmatterMatch[1].trim();

  const headingMatch = content.match(/^#\s+(.+)$/m);
  if (headingMatch) return headingMatch[1].trim();

  for (const line of content.split("\n")) {
    const trimmed = line.trim();
    if (trimmed && !trimmed.startsWith("---")) {
      return trimmed.slice(0, 100);
    }
  }

  return "No description";
}

function escapeXml(value: string): string {
  return value
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&apos;");
}

function loadProjectSkills(projectRoot: string): LoadedSkill[] {
  const loaded = new Map<string, LoadedSkill>();
  const skillDirs = getSkillSearchPaths(projectRoot);

  for (const skillsDir of skillDirs) {
    if (!CS.System.IO.Directory.Exists(skillsDir)) continue;

    const directories = CS.System.IO.Directory.GetDirectories(skillsDir);
    for (let i = 0; i < directories.Length; i++) {
      const dir = directories[i];
      const name = String(CS.System.IO.Path.GetFileName(dir) ?? "");
      const skillPath = CS.System.IO.Path.Combine(dir, "SKILL.md");
      if (!name || !CS.System.IO.File.Exists(skillPath)) continue;

      const content = String(CS.System.IO.File.ReadAllText(skillPath) ?? "");
      loaded.delete(name);
      loaded.set(name, {
        name,
        description: parseSkillDescription(content),
        source: "project",
        path: normalizePath(String(skillPath)),
      });
    }

    const files = CS.System.IO.Directory.GetFiles(skillsDir, "*.md");
    for (let i = 0; i < files.Length; i++) {
      const filePath = files[i];
      const fileName = String(CS.System.IO.Path.GetFileNameWithoutExtension(filePath) ?? "");
      if (!fileName) continue;

      const content = String(CS.System.IO.File.ReadAllText(filePath) ?? "");
      loaded.delete(fileName);
      loaded.set(fileName, {
        name: fileName,
        description: parseSkillDescription(content),
        source: "project",
        path: normalizePath(String(filePath)),
      });
    }
  }

  return Array.from(loaded.values());
}

export function getAvailableSkills(projectRoot: string): LoadedSkill[] {
  const skillMap = new Map<string, LoadedSkill>();

  for (const skill of BUILTIN_SKILLS) {
    skillMap.set(skill.name, skill);
  }

  for (const skill of loadProjectSkills(projectRoot)) {
    skillMap.set(skill.name, skill);
  }

  return Array.from(skillMap.values());
}

export function formatSkillsForPrompt(skills: LoadedSkill[]): string {
  if (!skills || skills.length === 0) {
    return "";
  }

  const lines = skills
    .slice()
    .sort((a, b) => a.name.localeCompare(b.name))
    .map((skill) => `- ${skill.name} [${skill.source}] - ${skill.description}`);

  return [
    "Project skills are available via the read_skill tool.",
    "Read a skill before relying on project-specific workflows or conventions.",
    "[Available Skills]",
    ...lines,
  ].join("\n");
}

export function readSkillContent(projectRoot: string, name: string): LoadedSkill | null {
  const skills = getAvailableSkills(projectRoot);
  const match = skills.find((skill) => skill.name === name);
  if (!match) return null;

  if (match.source === "builtin") {
    return match;
  }

  if (!match.path || !CS.System.IO.File.Exists(match.path)) {
    return null;
  }

  return {
    ...match,
    content: CS.System.IO.File.ReadAllText(match.path),
  };
}
