import type { AgentTool } from "@pie/agent-core";
import { Type } from "@sinclair/typebox";
import { readSkillContent } from "../skills.js";

export function createReadSkillTool(projectRoot: string): AgentTool {
  return {
    name: "read_skill",
    label: "read_skill",
    description: "Load the full contents of a builtin or project skill by name.",
    parameters: Type.Object({
      name: Type.String({ description: "Exact skill name from the available_skills list." }),
    }),
    execute: async (_toolCallId, params: { name: string }) => {
      const skill = readSkillContent(projectRoot, params.name);
      if (!skill?.content) {
        return {
          content: [{ type: "text" as const, text: `Skill not found: ${params.name}` }],
          details: { found: false, name: params.name },
          isError: true,
        };
      }

      return {
        content: [{
          type: "text" as const,
          text: `# ${skill.name}\nsource: ${skill.source}\n\n${skill.content}`,
        }],
        details: { found: true, name: skill.name, source: skill.source },
      };
    },
  };
}
