/**
 * HTTP client implementations for Node.js and PuerTS
 *
 * NOTE: Node.js modules are loaded dynamically via require to avoid
 * bundler issues when packaging for non-Node platforms (e.g., Meta Quest).
 */

import type { HttpClient, HttpResponse, HttpRequestOptions } from "./types.js";
import { createRequire } from "node:module";
import { fileURLToPath } from "node:url";
import { appendFileSync, existsSync, mkdirSync } from "node:fs";
import { dirname, join } from "node:path";

// Create require function for ESM compatibility
// @ts-ignore - import.meta.url is available in ESM
const __filename = fileURLToPath(import.meta.url);
const require = createRequire(__filename);

// ═══════════════════════════════════════════════════════════════════════════════
// Debug Logger
// ═══════════════════════════════════════════════════════════════════════════════

// Guard process.env access: in V8-only PuerTS, process is not available
const _procEnv: Record<string, string | undefined> =
  typeof process !== "undefined" ? process.env : {};

const DEBUG = _procEnv.PIE_DEBUG_HTTP === "1" || _procEnv.PIE_DEBUG_HTTP === "true";
const LOG_TO_FILE = _procEnv.PIE_DEBUG_HTTP_FILE === "1" || _procEnv.PIE_DEBUG_HTTP_FILE === "true";

let logFilePath: string | null = null;

function isTuiSessionActive(): boolean {
  return _procEnv.PIE_TUI_ACTIVE === "1" || _procEnv.PIE_TUI_ACTIVE === "true";
}

function initLogFile(): string | null {
  if (!LOG_TO_FILE) return null;
  try {
    const homeDir = _procEnv.HOME || _procEnv.USERPROFILE || "/tmp";
    const logDir = join(homeDir, ".pie", "logs");
    if (!existsSync(logDir)) {
      mkdirSync(logDir, { recursive: true });
    }
    logFilePath = join(logDir, `http-${new Date().toISOString().split("T")[0]}.log`);
    return logFilePath;
  } catch {
    return null;
  }
}

function logHttp(level: "INFO" | "DEBUG" | "WARN" | "ERROR", message: string, data?: Record<string, unknown>): void {
  const timestamp = new Date().toISOString();
  const prefix = `[${timestamp}] [HTTP:${level}]`;
  const logLine = data 
    ? `${prefix} ${message} ${JSON.stringify(data)}`
    : `${prefix} ${message}`;
  
  // In the interactive TUI, raw stderr corrupts the active editor/prompt line.
  // Keep writing to the debug file, but only mirror to stderr outside TUI.
  if (level === "ERROR" && !isTuiSessionActive()) {
    console.error(logLine);
  } else if (DEBUG) {
    console.error(logLine); // Use stderr to avoid interfering with stdout
  }

  // Write to file if enabled
  if (LOG_TO_FILE && logFilePath) {
    try {
      appendFileSync(logFilePath, logLine + "\n");
    } catch {
      // Ignore file write errors
    }
  }
}

function isAbortErrorMessage(message: string | undefined): boolean {
  return message === "Request was aborted" || message === "Operation aborted";
}

// Initialize log file on module load
initLogFile();

// ═══════════════════════════════════════════════════════════════════════════════
// Lazy-loaded Node.js modules - only loaded when actually needed
// ═══════════════════════════════════════════════════════════════════════════════

let nodeHttps: typeof import("https") | null = null;
let nodeHttp: typeof import("http") | null = null;
let nodeUrl: typeof import("url") | null = null;

function getNodeHttps(): typeof import("https") {
  if (!nodeHttps) {
    nodeHttps = require("https");
  }
  return nodeHttps!;
}

function getNodeHttp(): typeof import("http") {
  if (!nodeHttp) {
    nodeHttp = require("http");
  }
  return nodeHttp!;
}

function getNodeUrl(): typeof import("url") {
  if (!nodeUrl) {
    nodeUrl = require("url");
  }
  return nodeUrl!;
}

// ═══════════════════════════════════════════════════════════════════════════════
// Keep-Alive Connection Pool (Global Agents)
// ═══════════════════════════════════════════════════════════════════════════════

let globalHttpsAgent: import("https").Agent | null = null;
let globalHttpAgent: import("http").Agent | null = null;
let agentStats = {
  httpsRequests: 0,
  httpsReusedConnections: 0,
  httpRequests: 0,
  httpReusedConnections: 0,
};

/**
 * Get or create the global HTTPS agent with keep-alive enabled
 */
function getHttpsAgent(): import("https").Agent {
  if (!globalHttpsAgent) {
    const https = getNodeHttps();
    globalHttpsAgent = new https.Agent({
      keepAlive: true,
      maxSockets: 20,           // 最大并发连接数
      maxFreeSockets: 10,       // 保持空闲连接数
      timeout: 60000,           // 连接超时 60s
      scheduling: "lifo",       // 最近最少使用，优先复用
    } as import("https").AgentOptions);
    logHttp("INFO", "HTTPS Agent created with keep-alive", {
      maxSockets: 20,
      maxFreeSockets: 10,
      timeout: 60000,
    });
  }
  return globalHttpsAgent;
}

/**
 * Get or create the global HTTP agent with keep-alive enabled
 */
function getHttpAgent(): import("http").Agent {
  if (!globalHttpAgent) {
    const http = getNodeHttp();
    globalHttpAgent = new http.Agent({
      keepAlive: true,
      maxSockets: 20,
      maxFreeSockets: 10,
      timeout: 60000,
      scheduling: "lifo",
    } as import("http").AgentOptions);
    logHttp("INFO", "HTTP Agent created with keep-alive");
  }
  return globalHttpAgent;
}

/**
 * Get current agent statistics for debugging
 */
export function getAgentStats(): typeof agentStats {
  return { ...agentStats };
}

/**
 * Reset global agents (mainly for testing)
 */
export function resetAgents(): void {
  if (globalHttpsAgent) {
    globalHttpsAgent.destroy();
    globalHttpsAgent = null;
  }
  if (globalHttpAgent) {
    globalHttpAgent.destroy();
    globalHttpAgent = null;
  }
  agentStats = {
    httpsRequests: 0,
    httpsReusedConnections: 0,
    httpRequests: 0,
    httpReusedConnections: 0,
  };
  logHttp("INFO", "Agents reset");
}

/** Declare CS global for PuerTS Unity interop */
declare const CS: any;

// ═══════════════════════════════════════════════════════════════════════════════
// Node.js HTTP Client with Keep-Alive
// ═══════════════════════════════════════════════════════════════════════════════

/**
 * Node.js HTTP client using native https/http modules with connection pooling
 */
export class NodeHttpClient implements HttpClient {
  async request(url: string, options: HttpRequestOptions = {}): Promise<HttpResponse> {
    const requestStartTime = Date.now();
    const requestId = `${Date.now()}-${Math.random().toString(36).slice(2, 7)}`;
    
    logHttp("DEBUG", `Request [${requestId}] started`, {
      url: url.slice(0, 100),
      method: options.method || "GET",
      hasBody: !!options.body,
    });

    return new Promise((resolve, reject) => {
      const parsedUrl = new (getNodeUrl()).URL(url);
      const isHttps = parsedUrl.protocol === "https:";
      const lib = isHttps ? getNodeHttps() : getNodeHttp();
      const agent = isHttps ? getHttpsAgent() : getHttpAgent();

      // Update stats before request
      if (isHttps) {
        agentStats.httpsRequests++;
      } else {
        agentStats.httpRequests++;
      }

      const requestOptions = {
        hostname: parsedUrl.hostname,
        port: parsedUrl.port || (isHttps ? 443 : 80),
        path: parsedUrl.pathname + parsedUrl.search,
        method: options.method || "GET",
        headers: options.headers || {},
        agent: agent, // Use keep-alive agent
      };

      const connectStartTime = Date.now();

      const req = lib.request(requestOptions, (res: any) => {
        const connectTime = Date.now() - connectStartTime;
        
        // 检测连接是否复用：
        // 1. 首次连接通常 >100ms (TCP+TLS 握手)
        // 2. 复用连接通常 <20ms (直接从池中获取)
        // 3. Agent 的 socket 如果存在且已连接，说明是复用的
        const socket = res.socket;
        const agentInstance = isHttps ? globalHttpsAgent : globalHttpAgent;
        const hasFreeSockets = agentInstance && (agentInstance as any).freeSockets?.[parsedUrl.hostname];
        const wasReused = connectTime < 50 || !!(hasFreeSockets && socket?.readyState === 'open');
        
        if (wasReused) {
          if (isHttps) {
            agentStats.httpsReusedConnections++;
          } else {
            agentStats.httpReusedConnections++;
          }
        }

        logHttp("DEBUG", `Request [${requestId}] connected`, {
          status: res.statusCode,
          connectTimeMs: connectTime,
          connectionReused: wasReused,
          totalHttpsRequests: agentStats.httpsRequests,
          totalHttpsReused: agentStats.httpsReusedConnections,
        });

        const status = res.statusCode || 0;
        const responseHeaders: Record<string, string> = {};
        for (const [key, value] of Object.entries(res.headers)) {
          if (value) responseHeaders[key] = Array.isArray(value) ? value.join(", ") : String(value);
        }

        const response: HttpResponse = {
          status,
          statusText: res.statusMessage || "",
          ok: status >= 200 && status < 300,
          headers: responseHeaders,

          text(): Promise<string> {
            return new Promise((resolveText, rejectText) => {
              const chunks: Buffer[] = [];
              res.on("data", (chunk: Buffer) => chunks.push(chunk));
              res.on("end", () => {
                const body = Buffer.concat(chunks).toString("utf-8");
                logHttp("DEBUG", `Request [${requestId}] body received`, {
                  bodyLength: body.length,
                  totalTimeMs: Date.now() - requestStartTime,
                });
                resolveText(body);
              });
              res.on("error", (err: Error) => {
                logHttp("ERROR", `Request [${requestId}] body read error`, { error: err.message });
                rejectText(err);
              });
            });
          },

          async json(): Promise<any> {
            const text = await this.text();
            try {
              return JSON.parse(text);
            } catch (err) {
              logHttp("ERROR", `Request [${requestId}] JSON parse error`, {
                error: (err as Error).message,
                textPreview: text.slice(0, 200),
              });
              throw err;
            }
          },

          // ═════════════════════════════════════════════════════════════════
          // Optimized SSE streaming with Buffer queue (O(1) operations)
          // ═════════════════════════════════════════════════════════════════
          async *readSSELines(signal?: AbortSignal): AsyncIterable<string> {
            const sseStartTime = Date.now();
            let totalBytes = 0;
            let lineCount = 0;

            // Use Buffer queue instead of string concatenation for O(1) append
            let bufferChunks: Buffer[] = [];
            let bufferLength = 0;
            
            // Use a proper queue with head/tail pointers for O(1) dequeue
            const lineQueue: string[] = [];
            let queueHead = 0;
            
            let done = false;
            let error: Error | null = null;
            let waiting: ((value: { done: boolean; value?: string }) => void) | null = null;

            const flushBuffer = (): void => {
              if (bufferLength === 0) return;
              
              const buffer = Buffer.concat(bufferChunks, bufferLength);
              const bufferStr = buffer.toString("utf-8");
              const lines = bufferStr.split("\n");
              
              // Keep the last partial line in buffer
              const lastLine = lines.pop();
              if (lastLine !== undefined) {
                bufferChunks = [Buffer.from(lastLine)];
                bufferLength = lastLine.length;
              } else {
                bufferChunks = [];
                bufferLength = 0;
              }
              
              // Queue complete lines
              for (const line of lines) {
                lineQueue.push(line);
              }
            };

            if (signal) {
              signal.addEventListener("abort", () => {
                res.destroy();
              }, { once: true });
            }

            res.on("data", (chunk: Buffer) => {
              totalBytes += chunk.length;
              bufferChunks.push(chunk);
              bufferLength += chunk.length;
              
              // Flush buffer when it gets large enough or on newline
              if (bufferLength > 16384 || chunk.includes(0x0a)) { // 16KB or contains \n
                flushBuffer();
              }
              
              if (waiting) {
                const w = waiting;
                waiting = null;
                w({ done: false, value: undefined });
              }
            });

            res.on("end", () => {
              // Flush remaining buffer
              if (bufferLength > 0) {
                flushBuffer();
              }
              done = true;
              if (waiting) {
                const w = waiting;
                waiting = null;
                w({ done: true, value: undefined });
              }
              
              logHttp("DEBUG", `Request [${requestId}] SSE stream ended`, {
                totalBytes,
                lineCount,
                durationMs: Date.now() - sseStartTime,
              });
            });

            res.on("error", (e: Error) => {
              error = e;
              done = true;
              if (waiting) {
                const w = waiting;
                waiting = null;
                w({ done: true, value: undefined });
              }
              logHttp("ERROR", `Request [${requestId}] SSE stream error`, { error: e.message });
            });

            try {
              while (true) {
                // Yield queued lines with O(1) dequeue using head pointer
                while (queueHead < lineQueue.length) {
                  const line = lineQueue[queueHead++];
                  lineCount++;
                  yield line;
                }

                // Clean up queue when it gets large to prevent memory growth
                if (queueHead > 1000) {
                  lineQueue.splice(0, queueHead);
                  queueHead = 0;
                }

                if (done) {
                  if (error) throw error;
                  return;
                }

                // Wait for more data with proper backpressure handling
                const waitResult = await new Promise<{ done: boolean; value?: string }>((r) => {
                  waiting = r;
                });
                
                if (waitResult.done) break;
              }
            } finally {
              // Cleanup
              if (!done && !res.destroyed) {
                res.destroy();
              }
            }
          },
        };

        resolve(response);
      });

      req.on("error", (e: Error) => {
        if (isAbortErrorMessage(e.message) && options.signal?.aborted) {
          logHttp("DEBUG", `Request [${requestId}] aborted`, {
            totalTimeMs: Date.now() - requestStartTime,
          });
          reject(e);
          return;
        }
        logHttp("ERROR", `Request [${requestId}] failed`, {
          error: e.message,
          totalTimeMs: Date.now() - requestStartTime,
        });
        reject(e);
      });

      req.on("timeout", () => {
        logHttp("ERROR", `Request [${requestId}] timeout`);
        req.destroy(new Error("Request timeout"));
      });

      if (options.signal) {
        options.signal.addEventListener("abort", () => {
          logHttp("DEBUG", `Request [${requestId}] aborted`);
          req.destroy(new Error("Request was aborted"));
        }, { once: true });
      }

      if (options.body) {
        req.write(options.body);
      }
      req.end();
    });
  }
}

// ═══════════════════════════════════════════════════════════════════════════════
// PuerTS HTTP Client (Unity)
// ═══════════════════════════════════════════════════════════════════════════════

/**
 * PuerTS HTTP client using AgentBridge async HTTP methods (non-blocking)
 */
export class PuerTSHttpClient implements HttpClient {
  async request(url: string, options: HttpRequestOptions = {}): Promise<HttpResponse> {
    logHttp("DEBUG", `PuerTS Request started`, {
      url: url.slice(0, 100),
      method: options.method || "GET",
    });

    // Check for AgentBridge async HTTP methods (non-blocking)
    if (typeof CS !== "undefined" && CS?.AgentBridge?.HttpPostAsyncStart && CS?.AgentBridge?.HttpPostAsyncPoll) {
      const method = options.method || "GET";
      const body = options.body || "";
      const auth = options.headers?.Authorization || options.headers?.authorization || "";
      const authValue = auth.replace(/^Bearer\s+/i, "");

      console.log(`[PuerTSHttpClient] Using async HttpClient for ${url}`);

      // Start async request
      const requestId = CS.AgentBridge.HttpPostAsyncStart(url, body, authValue);
      console.log(`[PuerTSHttpClient] Request started: ${requestId}`);

      // Poll for completion (non-blocking yield to main thread)
      const maxWait = 120000; // 120 seconds
      const pollInterval = 50; // 50ms
      const startTime = Date.now();

      while (true) {
        // Check for abort signal
        if (options.signal?.aborted) {
          CS.AgentBridge.HttpPostAsyncCancel(requestId);
          throw new Error("Request was aborted");
        }

        // Poll for result (returns empty string if pending, JSON if complete)
        const pollResult = CS.AgentBridge.HttpPostAsyncPoll(requestId);
        console.log(`[PuerTSHttpClient] Poll result type: ${typeof pollResult}, length: ${pollResult?.length || 0}`);

        if (pollResult && pollResult.length > 0) {
          // Request complete
          const parsed = JSON.parse(pollResult);
          console.log(`[PuerTSHttpClient] Response status: ${parsed.statusCode}, body length: ${parsed.body?.length || 0}`);

          return {
            status: parsed.statusCode || 200,
            statusText: parsed.status === "ok" ? "OK" : "Error",
            ok: parsed.status === "ok",
            headers: { "content-type": "application/json" },

            text(): Promise<string> {
              return Promise.resolve(parsed.body || "");
            },

            async json(): Promise<any> {
              return JSON.parse(parsed.body || "{}");
            },

            async *readSSELines(signal?: AbortSignal): AsyncIterable<string> {
              const text = parsed.body || "";
              const lines = text.split('\n');
              for (const line of lines) {
                if (signal?.aborted) throw new Error("Request was aborted");
                yield line;
              }
            }
          };
        }

        // Check timeout
        if (Date.now() - startTime > maxWait) {
          CS.AgentBridge.HttpPostAsyncCancel(requestId);
          throw new Error("Request timed out");
        }

        // Yield to Unity main thread (critical for non-blocking!)
        await new Promise(resolve => setTimeout(resolve, pollInterval));
      }
    }

    // Fallback to UnityWebRequest if AgentBridge not available
    if (typeof CS === "undefined" || !CS?.UnityEngine?.Networking) {
      throw new Error("HTTP client not available - not running in PuerTS environment");
    }

    const { UnityEngine } = CS;
    const method = options.method || "GET";
    const headers = options.headers || {};
    const body = options.body;

    return new Promise((resolve, reject) => {
      // Create UnityWebRequest
      const request = new UnityEngine.Networking.UnityWebRequest(url, method);

      // Set headers
      for (const [key, value] of Object.entries(headers)) {
        request.SetRequestHeader(key, value);
      }

      // Set body for POST/PUT/PATCH
      if (body && ["POST", "PUT", "PATCH"].includes(method.toUpperCase())) {
        // Use TextEncoder to create Uint8Array - in PuerTS this should map to C# byte[]
        const encoder = new TextEncoder();
        const bodyData = encoder.encode(body);

        request.uploadHandler = new UnityEngine.Networking.UploadHandlerRaw(bodyData);
      }

      request.downloadHandler = new UnityEngine.Networking.DownloadHandlerBuffer();

      // Handle abort
      let aborted = false;
      if (options.signal) {
        const onAbort = () => {
          aborted = true;
          request.Abort();
          reject(new Error("Request was aborted"));
        };
        options.signal.addEventListener("abort", onAbort, { once: true });
      }

      // Send the request
      const asyncOp = request.SendWebRequest();

      // Wait for completion using coroutine-like polling
      const checkComplete = () => {
        if (aborted) return;

        if (asyncOp.isDone) {
          const status = request.responseCode;
          const ok = status >= 200 && status < 300;

          // Extract response headers
          const responseHeaders: Record<string, string> = {};
          const headerKeys = request.GetResponseHeaderKeys?.() || [];
          for (const key of headerKeys) {
            const value = request.GetResponseHeader(key);
            if (value) responseHeaders[key] = value;
          }

          const responseText = request.downloadHandler?.text || "";

          // Debug logging
          console.log(`[PuerTSHttpClient] Request completed: status=${status}, ok=${ok}, textLength=${responseText.length}`);

          resolve({
            status,
            statusText: request.error || "",
            ok,
            headers: responseHeaders,

            text(): Promise<string> {
              return Promise.resolve(responseText);
            },

            async json(): Promise<any> {
              return JSON.parse(responseText);
            },

            // SSE support for PuerTS - parse from complete response
            async *readSSELines(signal?: AbortSignal): AsyncIterable<string> {
              const text = responseText;
              const lines = text.split('\n');
              console.log(`[PuerTSHttpClient] readSSELines: ${lines.length} lines, first 100 chars: ${text.substring(0, 100)}`);

              for (const line of lines) {
                if (signal?.aborted) {
                  throw new Error("Request was aborted");
                }
                yield line;
              }
            }
          });
        } else {
          // Continue polling using Unity's coroutine-like approach
          // Note: setTimeout may not work in PuerTS, so we use a different approach
          if (typeof setTimeout !== 'undefined') {
            setTimeout(checkComplete, 10);
          } else {
            // Fallback: use a while loop with yield (less ideal but works)
            const startWait = Date.now();
            const wait = () => {
              if (!asyncOp.isDone && Date.now() - startWait < 30000) {
                if (typeof setImmediate !== 'undefined') {
                  setImmediate(wait);
                } else {
                  // Last resort: busy wait (not recommended but ensures completion)
                  checkComplete();
                }
              } else {
                checkComplete();
              }
            };
            wait();
          }
        }
      };

      checkComplete();
    });
  }
}
