/**
 * src/index.ts — pie-unity bundle entry point
 *
 * Executed by PieBridge.cs after core.js is loaded into the PuerTS V8 JsEnv.
 * Wires up:
 *   - UnityHttpClient → @pie/platform setHttpClient
 *   - @pie/tools-fs filesystem tools (sandboxed to projectRoot)
 *   - @pie/agent-core Agent instance
 *   - globalThis.pie.handleCSharpMessage for C# → JS messages
 *   - pieBridge.sendToUnity for JS → C# events
 */

// Side-effect import: registers openai-completions + anthropic-messages providers
import "@pie/ai";

import { Agent }              from "@pie/agent-core";
import type { AgentTool }     from "@pie/agent-core";
import { setHttpClient }      from "@pie/platform";
import { createEditTool, createLsTool, createReadTool, createWriteTool } from "@pie/tools-fs";
import type { Model }         from "@pie/ai";
import { UnityHttpClient }    from "./unity-http-client.js";
import { createEvalJsTool } from "./tools/eval-js.js";
import { createManageTodoListTool } from "./tools/manage-todo-list.js";
import { createNativeFindTool } from "./tools/native-find.js";
import { createNativeGrepTool } from "./tools/native-grep.js";
import { formatSkillsForPrompt, getAvailableSkills } from "./skills.js";
import { createInspectUnityContextTool, getUnityContextSnapshot } from "./tools/inspect-unity-context.js";
import { buildInitialProjectMemory, createWriteProjectMemoryTool, getProjectMemoryExcerpt, readProjectMemory } from "./tools/project-memory.js";
import { createSessionRecord, formatSessionTree, listSessions, loadSession, saveSession, type SessionRecord } from "./session-store.js";
import { loadProjectExtensions } from "./extensions/load-project-extensions.js";
import { buildRegisteredHooks, getExtensionTools, getLoadedExtensions, getSystemPromptPatches } from "./extensions/registry.js";
import { createReadSkillTool } from "./tools/read-skill.js";

// ─── Environment ──────────────────────────────────────────────────────────────

const bridge = (globalThis as any).pieBridge;
if (!bridge) throw new Error("[pie] globalThis.pieBridge not found — was PieBridge.cs initialized?");

const projectRoot: string = bridge.getProjectRoot();
const isEditor: boolean = bridge.isEditor === true;

// ─── HTTP Client Injection ────────────────────────────────────────────────────

// Replace the default HTTP client with one backed by PieHttpBridge.cs (true SSE streaming)
const httpClient = new UnityHttpClient();
setHttpClient(httpClient);

// ─── Provider Presets (must be defined before agent creation) ─────────────────

const PROVIDER_PRESETS: Record<string, { baseUrl: string; api: string }> = {
  "kimi-cn":    { baseUrl: "https://api.moonshot.cn/v1",           api: "openai-completions" },
  "moonshot":   { baseUrl: "https://api.moonshot.cn/v1",           api: "openai-completions" },
  "openai":     { baseUrl: "https://api.openai.com/v1",            api: "openai-completions" },
  "anthropic":  { baseUrl: "https://api.anthropic.com",            api: "anthropic-messages" },
  "openrouter": { baseUrl: "https://openrouter.ai/api/v1",         api: "openai-completions" },
  "bigmodel":   { baseUrl: "https://open.bigmodel.cn/api/paas/v4", api: "openai-completions" },
  "deepseek":   { baseUrl: "https://api.deepseek.com/v1",          api: "openai-completions" },
  "ollama":     { baseUrl: "http://localhost:11434/v1",             api: "openai-completions" },
};

const MODEL_PRESETS: Record<string, { provider: string; modelId: string; label: string }> = {
  "openai-fast": { provider: "openai", modelId: "gpt-4.1-mini", label: "GPT-4.1 mini" },
  "openai-strong": { provider: "openai", modelId: "gpt-4.1", label: "GPT-4.1" },
  "kimi-fast": { provider: "kimi-cn", modelId: "kimi-k2.5", label: "Kimi K2.5" },
  "claude-fast": { provider: "anthropic", modelId: "claude-3-5-haiku-latest", label: "Claude 3.5 Haiku" },
  "claude-strong": { provider: "anthropic", modelId: "claude-3-7-sonnet-latest", label: "Claude Sonnet" },
};

function getBaseConfig(provider: string): { baseUrl: string; api: string } {
  const preset = PROVIDER_PRESETS[provider.toLowerCase()];
  if (preset) return preset;

  for (const [key, val] of Object.entries(PROVIDER_PRESETS)) {
    if (provider.toLowerCase().startsWith(key)) return val;
  }

  return { baseUrl: `https://api.${provider}.com/v1`, api: "openai-completions" };
}

function buildSystemPrompt(root: string, editorMode: boolean): string {
  const skillsSection = formatSkillsForPrompt(getAvailableSkills(root));
  const projectMemory = getProjectMemoryExcerpt(root);
  const extensionSection = getSystemPromptPatches();
  const memorySection = projectMemory
    ? `\n\n[Project Memory]\n${projectMemory}\n---`
    : "";
  const extensionsPromptSection = extensionSection.length > 0
    ? `\n\n[Project Extensions]\n${extensionSection.join("\n\n---\n\n")}\n---`
    : "";

  if (editorMode) {
    return [
      "You are Pie, an expert AI coding assistant embedded in Unity Editor.",
      `The Unity project is located at: ${root}`,
      "You can work with files using these structured tools: read_file, write_file, edit_file, list_directory, search_file_content, search_files.",
      "You can execute JavaScript in Unity via the eval_js tool and the global CS object.",
      "Prefer making small, targeted edits. Always read a file before writing it.",
      "Be concise and helpful.",
      skillsSection,
      memorySection,
      extensionsPromptSection,
    ].join("\n");
  }

  return [
    "You are Pie, an AI agent running inside a Unity runtime application.",
    `Your primary working directory is: ${root}`,
    "You can work with files using these structured tools: read_file, write_file, edit_file, list_directory, search_file_content, search_files.",
    "You can execute JavaScript in Unity via the eval_js tool and the global CS object.",
    "You are intended for runtime automation, NPC behaviors, and voice-to-action control.",
    "Be concise and helpful.",
    skillsSection,
    memorySection,
    extensionsPromptSection,
  ].join("\n");
}

/**
 * Build a @pie/ai Model config from a provider name and model ID.
 */
function buildModel(provider: string, modelId: string): Model<any> {
  const base = getBaseConfig(provider);
  return {
    id: modelId,
    name: modelId,
    api: base.api,
    provider,
    baseUrl: base.baseUrl,
    reasoning: false,
    input: ["text"],
    cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0 },
    contextWindow: 128000,
    maxTokens: 8192,
  };
}

function aliasTool<T extends AgentTool<any>>(tool: T, name: string, label: string, description?: string): T {
  return {
    ...tool,
    name,
    label,
    description: description ?? tool.description,
  };
}

// ─── Config State ─────────────────────────────────────────────────────────────

let _apiKey   = "";
let _provider = "openai";
let _modelId  = "gpt-4.1-mini";
let _verboseLogs = false;
let _currentSession: SessionRecord = createSessionRecord({
  provider: _provider,
  modelId: _modelId,
  messages: [],
  todoState: [],
});

// ─── Agent ────────────────────────────────────────────────────────────────────

const todoTool = createManageTodoListTool();
const builtinFileTools = [
  aliasTool(
    createReadTool(projectRoot),
    "read_file",
    "read_file",
    "Read a file by relative path. Example: read_file path='Assets/Scripts/DemoScript.cs'.",
  ),
  aliasTool(
    createWriteTool(projectRoot),
    "write_file",
    "write_file",
    "Write a full file by relative path. Example: write_file path='Assets/Scripts/DemoScript.cs' content='...'.",
  ),
  aliasTool(
    createEditTool(projectRoot),
    "edit_file",
    "edit_file",
    "Edit an existing file by replacing exact oldText with newText. Read the file first so oldText matches exactly.",
  ),
  aliasTool(
    createLsTool(projectRoot),
    "list_directory",
    "list_directory",
    "List a directory by relative path. Example: list_directory path='Assets/Scripts'.",
  ),
  aliasTool(
    createNativeGrepTool(projectRoot),
    "search_file_content",
    "search_file_content",
    "Search inside files for text or regex. Best practice: pattern='MonoBehaviour', glob='*.cs', literal=true.",
  ),
  aliasTool(
    createNativeFindTool(projectRoot),
    "search_files",
    "search_files",
    "Search for files by filename fragment or glob pattern. Best practice: use a simple filename like 'DemoScript' or 'DemoScript.cs'. Do not pass a shell command.",
  ),
];

function createBuiltinTools() {
  return [
    ...builtinFileTools,
    createEvalJsTool(),
    todoTool.tool,
    createReadSkillTool(projectRoot),
  ];
}

function rebuildAgentSurface() {
  const tools = [
    ...createBuiltinTools(),
    ...getExtensionTools(),
  ];
  agent.setTools(tools);
  const hooks = buildRegisteredHooks();
  const setHooks = (agent as any).setHooks;
  if (typeof setHooks === "function") {
    setHooks.call(agent, hooks);
  } else if (hooks) {
    bridge.log("warn", "[pie/extensions] Agent hooks are not available in this build; registered hooks will be ignored.");
  }
  agent.setSystemPrompt(buildSystemPrompt(projectRoot, isEditor));
}

const agent = new Agent({
  initialState: {
    systemPrompt: buildSystemPrompt(projectRoot, isEditor),
    model: buildModel(_provider, _modelId),
    tools: createBuiltinTools(),
  },
  sessionId: _currentSession.id,
  getApiKey: () => _apiKey || undefined,
});

function syncSessionInfo() {
  agent.sessionId = _currentSession.id;
}

function verboseLog(message: string) {
  if (_verboseLogs) {
    bridge.log("info", message);
  }
}

function reloadProjectExtensions() {
  const result = loadProjectExtensions({
    projectRoot,
    isEditor,
    log: verboseLog,
  });
  rebuildAgentSurface();
  return result;
}

function persistCurrentSession() {
  _currentSession = saveSession(projectRoot, {
    ..._currentSession,
    provider: _provider,
    modelId: _modelId,
    messages: agent.state.messages.slice(),
    todoState: todoTool.getState(),
  });
  syncSessionInfo();
}

function startFreshSession(parentSessionId?: string) {
  _currentSession = createSessionRecord({
    parentSessionId,
    provider: _provider,
    modelId: _modelId,
    messages: [],
    todoState: [],
  });
  agent.reset();
  agent.setModel(buildModel(_provider, _modelId));
  rebuildAgentSurface();
  todoTool.reset();
  syncSessionInfo();
}

function restoreSessionRecord(record: SessionRecord) {
  _currentSession = record;
  _provider = record.provider || _provider;
  _modelId = record.modelId || _modelId;
  agent.reset();
  agent.replaceMessages(record.messages || []);
  agent.resetProcessingState();
  agent.setModel(buildModel(_provider, _modelId));
  rebuildAgentSurface();
  todoTool.restore(record.todoState || []);
  syncSessionInfo();
}

function forkFromRecord(record: SessionRecord) {
  const forked = createSessionRecord({
    parentSessionId: record.id,
    provider: record.provider || _provider,
    modelId: record.modelId || _modelId,
    messages: (record.messages || []).slice(),
    todoState: (record.todoState || []).slice(),
  });
  restoreSessionRecord(forked);
  persistCurrentSession();
}

function emitLocalAssistantMessage(text: string) {
  bridge.sendToUnity("message_update", { type: "text_full", text });
  bridge.sendToUnity("turn_end", { role: "assistant", stopReason: "stop" });
  bridge.sendToUnity("agent_end", {});
}

function emitSkillsList() {
  const skills = getAvailableSkills(projectRoot).map((skill) => ({
    name: skill.name,
    description: skill.description,
    source: skill.source,
    path: skill.path || "",
  }));
  bridge.sendToUnity("skills_list", { skills });
}

function applyModelSelection(provider: string, modelId: string) {
  _provider = provider;
  _modelId = modelId;
  agent.setModel(buildModel(_provider, _modelId));
  rebuildAgentSurface();
  persistCurrentSession();
}

function extractToolText(result: any): string {
  if (!result) return "";
  if (typeof result === "string") return result;
  if (Array.isArray(result.content)) {
    return result.content
      .filter((item: any) => item?.type === "text")
      .map((item: any) => String(item.text ?? ""))
      .join("\n")
      .trim();
  }
  return "";
}

function extractEffectiveArgs(toolName: string, args: any, details: any): any {
  if (toolName === "search_files") {
    return {
      rawPattern: details?.rawPattern ?? args?.pattern ?? args?.query ?? args?.name ?? args?.file_name ?? "",
      pattern: details?.effectivePattern ?? args?.pattern ?? args?.query ?? args?.name ?? args?.file_name ?? "",
      path: details?.searchPath ?? args?.path ?? ".",
      limit: args?.limit,
    };
  }

  if (toolName === "search_file_content") {
    return {
      pattern: details?.effectivePattern ?? args?.pattern ?? "",
      glob: details?.glob ?? args?.glob ?? "",
      path: details?.searchPath ?? args?.path ?? ".",
      literal: details?.literal ?? args?.literal,
      ignoreCase: details?.ignoreCase ?? args?.ignoreCase,
      limit: args?.limit,
    };
  }

  return args ?? {};
}

function handleLocalCommand(content: string): boolean {
  const trimmed = content.trim();
  if (!trimmed.startsWith("/")) return false;

  const [command, ...rest] = trimmed.split(/\s+/);
  if (command === "/new") {
    persistCurrentSession();
    startFreshSession();
    emitLocalAssistantMessage(`Started new session: ${_currentSession.id}`);
    return true;
  }

  if (command === "/resume") {
    const sessionId = rest[0];
    if (!sessionId) {
      const sessions = listSessions(projectRoot);
      const text = sessions.length === 0
        ? "No saved sessions."
        : sessions.map((session) => `${session.id} | ${session.title} | ${session.modelId} | ${session.updatedAt}`).join("\n");
      emitLocalAssistantMessage(text);
      return true;
    }

    const loaded = loadSession(projectRoot, sessionId);
    if (!loaded) {
      emitLocalAssistantMessage(`Session not found: ${sessionId}`);
      return true;
    }

    restoreSessionRecord(loaded);
    emitLocalAssistantMessage(`Resumed session ${loaded.id}\nTitle: ${loaded.title}\nMessages: ${loaded.messageCount}`);
    return true;
  }

  if (command === "/tree") {
    emitLocalAssistantMessage(formatSessionTree(projectRoot));
    return true;
  }

  if (command === "/session-check") {
    const probe = createSessionRecord({
      sessionId: `probe_${Date.now().toString(36)}`,
      provider: _provider,
      modelId: _modelId,
      messages: agent.state.messages.slice(),
      todoState: todoTool.getState(),
    });
    const saved = saveSession(projectRoot, probe);
    const loaded = loadSession(projectRoot, saved.id);
    const ok = !!loaded
      && loaded.id === saved.id
      && loaded.provider === saved.provider
      && loaded.modelId === saved.modelId
      && (loaded.messages?.length || 0) === saved.messages.length
      && (loaded.todoState?.length || 0) === saved.todoState.length;

    emitLocalAssistantMessage(
      ok
        ? `Session self-check passed.\nSession: ${saved.id}\nMessages: ${saved.messages.length}\nTodos: ${saved.todoState.length}`
        : `Session self-check failed.\nSaved: ${saved.id}\nLoaded: ${loaded ? loaded.id : "(missing)"}`,
    );
    return true;
  }

  if (command === "/fork") {
    const sessionId = rest[0];
    if (sessionId) {
      const source = loadSession(projectRoot, sessionId);
      if (!source) {
        emitLocalAssistantMessage(`Session not found: ${sessionId}`);
        return true;
      }
      forkFromRecord(source);
      emitLocalAssistantMessage(`Forked new session ${_currentSession.id} from ${source.id}`);
      return true;
    }

    persistCurrentSession();
    const source = loadSession(projectRoot, _currentSession.id) || _currentSession;
    forkFromRecord(source);
    emitLocalAssistantMessage(`Forked new session ${_currentSession.id} from ${source.id}`);
    return true;
  }

  if (command === "/memory") {
    const memory = readProjectMemory(projectRoot);
    emitLocalAssistantMessage(
      memory
        ? `Project memory loaded from Assets/Pie/AGENTS.md\n\n${memory}`
        : "No project memory found. Use /init to create an initial AGENTS.md.",
    );
    return true;
  }

  if (command === "/model") {
    if (rest.length === 0) {
      const presets = Object.entries(MODEL_PRESETS)
        .map(([key, value]) => `${key} => ${value.provider}/${value.modelId} (${value.label})`)
        .join("\n");
      emitLocalAssistantMessage(`Current model: ${_provider}/${_modelId}\n\nPresets:\n${presets}`);
      return true;
    }

    if (rest.length === 1) {
      const preset = MODEL_PRESETS[rest[0]];
      if (!preset) {
        emitLocalAssistantMessage(`Unknown model preset: ${rest[0]}`);
        return true;
      }
      applyModelSelection(preset.provider, preset.modelId);
      emitLocalAssistantMessage(`Switched model to ${preset.provider}/${preset.modelId}`);
      return true;
    }

    const provider = rest[0];
    const modelId = rest.slice(1).join(" ");
    applyModelSelection(provider, modelId);
    emitLocalAssistantMessage(`Switched model to ${provider}/${modelId}`);
    return true;
  }

  if (command === "/skills") {
    const subcommand = rest[0] || "list";
    if (subcommand === "reload") {
      rebuildAgentSurface();
      const skills = getAvailableSkills(projectRoot);
      emitSkillsList();
      emitLocalAssistantMessage(`Reloaded ${skills.length} skill(s).`);
      return true;
    }

    const skills = getAvailableSkills(projectRoot);
    emitSkillsList();
    if (skills.length === 0) {
      emitLocalAssistantMessage("No skills available.");
      return true;
    }
    emitLocalAssistantMessage(
      skills
        .map((skill) => `${skill.name} [${skill.source}] - ${skill.description}`)
        .join("\n"),
    );
    return true;
  }

  if (command === "/extensions") {
    const subcommand = rest[0] || "list";
    if (subcommand === "reload") {
      const result = reloadProjectExtensions();
      const loaded = getLoadedExtensions();
      const loadedText = loaded.length > 0 ? loaded.join("\n") : "(none)";
      const errorText = result.errors.length > 0 ? `\n\nErrors:\n${result.errors.join("\n")}` : "";
      emitLocalAssistantMessage(`Reloaded ${loaded.length} extension(s).\n\n${loadedText}${errorText}`);
      return true;
    }

    const loaded = getLoadedExtensions();
    emitLocalAssistantMessage(
      loaded.length > 0
        ? `Loaded extensions:\n${loaded.join("\n")}`
        : "No project extensions loaded. Add .js files under Assets/Pie/Extensions or configure additional search paths in Pie Settings.",
    );
    return true;
  }

  if (command === "/init") {
    const snapshot = getUnityContextSnapshot(projectRoot, isEditor);
    const initialMemory = buildInitialProjectMemory(snapshot);
    const writeTool = createWriteProjectMemoryTool(projectRoot);
    writeTool.execute("local-init", { content: initialMemory });
    agent.setSystemPrompt(buildSystemPrompt(projectRoot, isEditor));
    emitLocalAssistantMessage(`Initialized project memory at Assets/Pie/AGENTS.md\n\n${initialMemory}`);
    return true;
  }

  return false;
}

// ─── Event forwarding: Agent → C# ─────────────────────────────────────────────

reloadProjectExtensions();

agent.subscribe((event) => {
  try {
    switch (event.type) {
      case "agent_start":
        bridge.sendToUnity("state_event", { name: "agent_start", detail: "agent loop started" });
        break;

      case "turn_start":
        bridge.sendToUnity("state_event", { name: "turn_start", detail: "turn started" });
        break;

      case "message_start":
        bridge.sendToUnity("state_event", { name: "message_start", detail: `role=${(event.message as any)?.role ?? "assistant"}` });
        break;

      case "message_update": {
        const msg = event.message;
        const text = Array.isArray(msg.content)
          ? msg.content
              .filter((c: any) => c?.type === "text")
              .map((c: any) => c.text)
              .join("")
          : "";
        if (event.assistantMessageEvent?.type === "thinking_start") {
          bridge.sendToUnity("thinking_event", { type: "start" });
        } else if (event.assistantMessageEvent?.type === "thinking_delta") {
          bridge.sendToUnity("thinking_event", {
            type: "delta",
            delta: (event.assistantMessageEvent as any).delta ?? "",
          });
        } else if (event.assistantMessageEvent?.type === "thinking_end") {
          bridge.sendToUnity("thinking_event", {
            type: "end",
            text: (event.assistantMessageEvent as any).content ?? "",
          });
        }
        bridge.sendToUnity("state_event", {
          name: "message_update",
          detail: `type=${event.assistantMessageEvent?.type ?? "text"} chars=${text.length}`,
        });
        if (text) {
          bridge.sendToUnity("message_update",
            { type: "text_full", text });
        }
        break;
      }

      case "message_end":
        bridge.sendToUnity("state_event", { name: "message_end", detail: `role=${(event.message as any)?.role ?? "assistant"}` });
        break;

      case "tool_execution_start":
        verboseLog(`[tool_start payload] ${JSON.stringify({
          name: event.toolName,
          callId: event.toolCallId,
          argsJson: JSON.stringify(event.args ?? {}).substring(0, 4000),
        })}`);
        bridge.sendToUnity("tool_start",
          {
            name: event.toolName,
            callId: event.toolCallId,
            argsJson: JSON.stringify(event.args ?? {}).substring(0, 4000),
          });
        break;

      case "tool_execution_end":
        {
          const effectiveArgs = extractEffectiveArgs(event.toolName, event.args, event.result?.details);
          const resultText = extractToolText(event.result).substring(0, 4000);
          const resultJson = JSON.stringify(event.result ?? "").substring(0, 4000);
          const detailsJson = event.result?.details !== undefined
            ? JSON.stringify(event.result.details).substring(0, 4000)
            : "";
        verboseLog(`[tool_end payload] ${JSON.stringify({
          name: event.toolName,
          callId: event.toolCallId,
          argsJson: JSON.stringify(event.args ?? {}).substring(0, 4000),
          effectiveArgsJson: JSON.stringify(effectiveArgs ?? {}).substring(0, 4000),
          isError: !!(event as any).isError,
        })}`);
        bridge.sendToUnity("tool_end", {
          name: event.toolName,
          callId: event.toolCallId,
          argsJson: JSON.stringify(event.args ?? {}).substring(0, 4000),
          effectiveArgsJson: JSON.stringify(effectiveArgs ?? {}).substring(0, 4000),
          isError: !!(event as any).isError,
          resultText,
          resultJson,
          detailsJson,
          error: (event as any).error
            ? String((event as any).error?.message ?? (event as any).error).substring(0, 4000)
            : (event as any).isError
              ? resultText || "Tool returned an error result."
              : undefined,
        });
        }
        break;

      case "turn_end":
        persistCurrentSession();
        bridge.sendToUnity("turn_end",
          { role: event.message.role, stopReason: (event as any).message?.stopReason ?? "stop" });
        bridge.sendToUnity("state_event", {
          name: "turn_end",
          detail: `stopReason=${(event as any).message?.stopReason ?? "stop"}`,
        });
        // If the turn ended with an error, also send an explicit error event so C# can show it
        if ((event as any).message?.stopReason === "error" || (event as any).message?.stopReason === "aborted") {
          const errMsg: string = (event as any).message?.errorMessage ?? "Request failed";
          bridge.sendToUnity("error", { message: errMsg });
        }
        break;

      case "agent_end":
        bridge.sendToUnity("state_event", { name: "agent_end", detail: "agent loop finished" });
        bridge.sendToUnity("agent_end", {});
        break;
    }
  } catch (err: any) {
    bridge.log("error", `[pie/index] Event forwarding error: ${err?.message || err}`);
  }
});

// ─── Public API: C# → JS ──────────────────────────────────────────────────────

(globalThis as any).pie = {
  /**
   * Entry point called by PieBridge.cs via jsEnv.Eval("pie.handleCSharpMessage(action, data)").
   * data is a plain JS object (already parsed from JSON by JsEnv eval).
   */
  handleCSharpMessage: async function(action: string, data: any): Promise<void> {
    try {
      switch (action) {
        case "send_message": {
          const content = (data && typeof data.content === "string") ? data.content : String(data);
          if (handleLocalCommand(content)) {
            break;
          }
          // Run agent (non-blocking: we don't await here, result comes via events)
          agent.prompt(content).catch((err: any) => {
            const msg = err?.message || String(err);
            bridge.log("error", `[pie/index] agent.prompt rejected: ${msg}`);
            bridge.sendToUnity("error", { message: msg });
          });
          break;
        }

        case "set_config": {
          if (data?.apiKey   !== undefined) _apiKey   = data.apiKey;
          if (data?.provider !== undefined) _provider = data.provider;
          if (data?.model    !== undefined) _modelId  = data.model;
          if (data?.verboseLogs !== undefined) _verboseLogs = data.verboseLogs === true;
          (globalThis as any).__pieVerboseLogs = _verboseLogs;

          // Update agent model
          applyModelSelection(_provider, _modelId);

          break;
        }

        case "new_session": {
          persistCurrentSession();
          startFreshSession();
          break;
        }

        case "list_skills": {
          emitSkillsList();
          break;
        }

        case "reload_skills": {
          rebuildAgentSurface();
          emitSkillsList();
          break;
        }

        case "abort": {
          agent.abort();
          break;
        }

        default:
          bridge.log("warn", `[pie/index] Unknown action: ${action}`);
      }
    } catch (err: any) {
      const msg = err?.message || String(err);
      bridge.log("error", `[pie/index] Error in ${action}: ${msg}`);
      bridge.sendToUnity("error", { message: msg });
    }
  }
};
