/**
 * Grep tool - Search file contents for a pattern.
 */

import type { AgentTool } from "@pie/agent-core";
import type { Static } from "@sinclair/typebox";
import { Type } from "@sinclair/typebox";
import { detectPlatform, getFileSystem } from "@pie/platform";
import { resolveToCwd, type PathResolutionOptions } from "./path-utils.js";
import {
	DEFAULT_MAX_BYTES,
	formatSize,
	GREP_MAX_LINE_LENGTH,
	type TruncationResult,
	truncateHead,
	truncateLine,
} from "./truncate.js";

const grepSchema = Type.Object({
	pattern: Type.String({ description: "Search pattern (regex or literal string)" }),
	path: Type.Optional(Type.String({ description: "Directory or file to search (default: sandbox root)" })),
	glob: Type.Optional(Type.String({ description: "Filter files by glob pattern, e.g. '*.ts' or '**/*.js'" })),
	ignoreCase: Type.Optional(Type.Boolean({ description: "Case-insensitive search (default: false)" })),
	literal: Type.Optional(
		Type.Boolean({ description: "Treat pattern as literal string instead of regex (default: false)" }),
	),
	context: Type.Optional(
		Type.Number({ description: "Number of lines to show before and after each match (default: 0)" }),
	),
	limit: Type.Optional(Type.Number({ description: "Maximum number of matches to return (default: 100)" })),
});

export type GrepToolInput = Static<typeof grepSchema>;

const DEFAULT_LIMIT = 100;

declare const CS: any;

export interface GrepToolDetails {
	truncation?: TruncationResult;
	matchLimitReached?: number;
	linesTruncated?: boolean;
}

// Directories and files to skip during recursive search
const SKIP_DIRS = new Set([".git", "node_modules", "__pycache__", ".svn", ".hg"]);
const BINARY_EXTENSIONS = new Set([
	".png", ".jpg", ".jpeg", ".gif", ".bmp", ".ico", ".webp",
	".mp3", ".mp4", ".wav", ".avi", ".mov",
	".zip", ".tar", ".gz", ".bz2", ".7z", ".rar",
	".exe", ".dll", ".so", ".dylib", ".bin",
	".pdf", ".doc", ".docx", ".xls", ".xlsx",
	".woff", ".woff2", ".ttf", ".eot",
]);

interface NativeGrepResult {
	Lines?: string[];
	MatchCount?: number;
	MatchLimitReached?: boolean;
	LinesTruncated?: boolean;
	FilesScanned?: number;
}

function getNativeFileBridge(): any | null {
	try {
		return typeof CS !== "undefined" && CS?.Pie?.PieFileBridge ? CS.Pie.PieFileBridge : null;
	} catch {
		return null;
	}
}

type FileCompletionRecord = { resultJson: string | null; error: string | null };
type FileCompletionStore = {
	completions: Map<number, FileCompletionRecord>;
	waiters: Map<number, (value: FileCompletionRecord) => void>;
};

function getFileCompletionStore(): FileCompletionStore {
	const g = globalThis as any;
	if (!g.__pieFileCompletionStore) {
		g.__pieFileCompletionStore = {
			completions: new Map<number, FileCompletionRecord>(),
			waiters: new Map<number, (value: FileCompletionRecord) => void>(),
		};
	}

	if (!g._pieFileComplete) {
		g._pieFileComplete = (requestId: number, resultJson: string | null, error: string | null) => {
			const store = getFileCompletionStore();
			const payload = { resultJson, error };
			store.completions.set(requestId, payload);
			const waiter = store.waiters.get(requestId);
			if (waiter) {
				store.waiters.delete(requestId);
				waiter(payload);
			}
		};
	}

	return g.__pieFileCompletionStore as FileCompletionStore;
}

function waitForFileCompletion(requestId: number): Promise<FileCompletionRecord> {
	const store = getFileCompletionStore();
	const existing = store.completions.get(requestId);
	if (existing) {
		return Promise.resolve(existing);
	}

	return new Promise<FileCompletionRecord>((resolve) => {
		store.waiters.set(requestId, resolve);
	});
}

async function runNativeGrep(
	searchPath: string,
	pattern: string,
	globPattern: string | undefined,
	ignoreCase: boolean,
	literal: boolean,
	contextLines: number,
	limit: number,
	signal?: AbortSignal,
): Promise<NativeGrepResult> {
	const bridge = getNativeFileBridge();
	if (!bridge) {
		throw new Error("CS.Pie.PieFileBridge not available");
	}

	const requestId = bridge.StartGrep(
		searchPath,
		pattern,
		globPattern ?? "",
		!!ignoreCase,
		!!literal,
		contextLines,
		limit,
	);

	const onAbort = () => bridge.CancelRequest(requestId);
	signal?.addEventListener("abort", onAbort, { once: true });

	try {
		if (signal?.aborted) {
			bridge.CancelRequest(requestId);
			throw new Error("Operation aborted");
		}

		const completion = await waitForFileCompletion(requestId);
		if (completion.error) {
			throw new Error(completion.error);
		}

		if (!completion.resultJson) {
			return {};
		}

		return JSON.parse(completion.resultJson) as NativeGrepResult;
	} finally {
		const store = getFileCompletionStore();
		store.completions.delete(requestId);
		store.waiters.delete(requestId);
		signal?.removeEventListener("abort", onAbort);
		bridge.ReleaseRequest(requestId);
	}
}

/**
 * Recursively collect all files in a directory.
 */
async function collectFiles(dirPath: string, globPattern: string | undefined, fs: any): Promise<string[]> {
	const files: string[] = [];
	const queue = [dirPath];

	while (queue.length > 0) {
		const dir = queue.pop()!;
		let entries: string[];
		try {
			entries = await fs.readdir(dir);
		} catch {
			continue;
		}

		for (const entry of entries) {
			const fullPath = fs.join(dir, entry);
			let stat: any;
			try {
				stat = await fs.stat(fullPath);
			} catch {
				continue;
			}

			if (stat.isDirectory) {
				if (!SKIP_DIRS.has(entry)) {
					queue.push(fullPath);
				}
			} else if (stat.isFile) {
				const ext = fs.extname(entry).toLowerCase();
				if (BINARY_EXTENSIONS.has(ext)) continue;

				// Apply glob filter (simple extension matching)
				if (globPattern) {
					if (globPattern.startsWith("*.")) {
						const globExt = globPattern.slice(1); // e.g. ".ts"
						if (ext !== globExt) continue;
					} else if (globPattern.startsWith("**/*.")) {
						const globExt = globPattern.slice(3); // e.g. ".ts"
						if (ext !== globExt) continue;
					}
				}

				files.push(fullPath);
			}
		}
	}

	return files;
}

export function createGrepTool(
	cwd: string,
	options?: PathResolutionOptions,
): AgentTool<typeof grepSchema> {
	const fs = getFileSystem();
	const platform = detectPlatform();

	return {
		name: "grep",
		label: "grep",
		description: `Search file contents for a pattern. Returns matching lines with file paths and line numbers. Output is truncated to ${DEFAULT_LIMIT} matches or ${DEFAULT_MAX_BYTES / 1024}KB (whichever is hit first). Long lines are truncated to ${GREP_MAX_LINE_LENGTH} chars.`,
		parameters: grepSchema,
		execute: async (
			_toolCallId: string,
			{
				pattern,
				path: searchDir,
				glob: globPattern,
				ignoreCase,
				literal,
				context: contextLines,
				limit,
			}: {
				pattern: string;
				path?: string;
				glob?: string;
				ignoreCase?: boolean;
				literal?: boolean;
				context?: number;
				limit?: number;
			},
			signal?: AbortSignal,
		) => {
			return new Promise((resolve, reject) => {
				if (signal?.aborted) {
					reject(new Error("Operation aborted"));
					return;
				}

				const onAbort = () => reject(new Error("Operation aborted"));
				signal?.addEventListener("abort", onAbort, { once: true });

				(async () => {
					try {
						const searchPath = resolveToCwd(searchDir || ".", cwd, options);
						const effectiveLimit = Math.max(1, limit ?? DEFAULT_LIMIT);
						const ctx = contextLines && contextLines > 0 ? contextLines : 0;

						let isDir: boolean;
						try {
							const stat = await fs.stat(searchPath);
							isDir = stat.isDirectory;
						} catch {
							reject(new Error(`Path not found: ${searchPath}`));
							return;
						}

						// Build regex
						let regex: RegExp;
						try {
							const flags = ignoreCase ? "gi" : "g";
							if (literal) {
								const escaped = pattern.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
								regex = new RegExp(escaped, flags);
							} else {
								regex = new RegExp(pattern, flags);
							}
						} catch (e: any) {
							reject(new Error(`Invalid regex pattern: ${e.message}`));
							return;
						}

						let outputLines: string[] = [];
						let matchCount = 0;
						let matchLimitReached = false;
						let linesTruncated = false;

						if (platform === "puerts" && getNativeFileBridge()) {
							const nativeResult = await runNativeGrep(
								searchPath,
								pattern,
								globPattern,
								!!ignoreCase,
								!!literal,
								ctx,
								effectiveLimit,
								signal,
							);
							outputLines = nativeResult.Lines ?? [];
							matchCount = nativeResult.MatchCount ?? 0;
							matchLimitReached = !!nativeResult.MatchLimitReached;
							linesTruncated = !!nativeResult.LinesTruncated;
							(globalThis as any).pieBridge?.log?.(
								"info",
								`[grep] path=${searchPath} pattern=${pattern} matches=${matchCount} files=${nativeResult.FilesScanned ?? 0}`,
							);
						} else {
							// Collect files to search
							let filePaths: string[];
							if (isDir) {
								filePaths = await collectFiles(searchPath, globPattern, fs);
								filePaths.sort();
							} else {
								filePaths = [searchPath];
							}

							for (const filePath of filePaths) {
								if (matchCount >= effectiveLimit) {
									matchLimitReached = true;
									break;
								}

								if (signal?.aborted) {
									reject(new Error("Operation aborted"));
									return;
								}

								let content: string;
								try {
									content = await fs.readFile(filePath, "utf-8");
								} catch {
									continue;
								}

								const lines = content.replace(/\r\n/g, "\n").replace(/\r/g, "\n").split("\n");
								const relativePath = isDir
									? fs.relative(searchPath, filePath)
									: fs.basename(filePath);

								for (let lineIdx = 0; lineIdx < lines.length; lineIdx++) {
									if (matchCount >= effectiveLimit) {
										matchLimitReached = true;
										break;
									}

									regex.lastIndex = 0;
									if (regex.test(lines[lineIdx])) {
										matchCount++;
										const start = ctx > 0 ? Math.max(0, lineIdx - ctx) : lineIdx;
										const end = ctx > 0 ? Math.min(lines.length - 1, lineIdx + ctx) : lineIdx;

										for (let c = start; c <= end; c++) {
											const lineText = lines[c];
											const { text: truncatedText, wasTruncated } = truncateLine(lineText);
											if (wasTruncated) linesTruncated = true;

											const currentLineNum = c + 1;
											if (c === lineIdx) {
												outputLines.push(`${relativePath}:${currentLineNum}: ${truncatedText}`);
											} else {
												outputLines.push(`${relativePath}-${currentLineNum}- ${truncatedText}`);
											}
										}
									}
								}
							}
						}

						signal?.removeEventListener("abort", onAbort);

						if (matchCount === 0) {
							resolve({ content: [{ type: "text", text: "No matches found" }], details: undefined, isError: true });
							return;
						}

						const rawOutput = outputLines.join("\n");
						const truncation = truncateHead(rawOutput, { maxLines: Number.MAX_SAFE_INTEGER });

						let output = truncation.content;
						const details: GrepToolDetails = {};
						const notices: string[] = [];

						if (matchLimitReached) {
							notices.push(
								`${effectiveLimit} matches limit reached. Use limit=${effectiveLimit * 2} for more, or refine pattern`,
							);
							details.matchLimitReached = effectiveLimit;
						}

						if (truncation.truncated) {
							notices.push(`${formatSize(DEFAULT_MAX_BYTES)} limit reached`);
							details.truncation = truncation;
						}

						if (linesTruncated) {
							notices.push(
								`Some lines truncated to ${GREP_MAX_LINE_LENGTH} chars. Use read tool to see full lines`,
							);
							details.linesTruncated = true;
						}

						if (notices.length > 0) {
							output += `\n\n[${notices.join(". ")}]`;
						}

						resolve({
							content: [{ type: "text", text: output }],
							details: Object.keys(details).length > 0 ? details : undefined,
						});
					} catch (err) {
						signal?.removeEventListener("abort", onAbort);
						reject(err as Error);
					}
				})();
			});
		},
	};
}
