/**
 * Ls tool - List directory contents.
 */

import type { AgentTool } from "@pie/agent-core";
import type { Static } from "@sinclair/typebox";
import { Type } from "@sinclair/typebox";
import { getFileSystem } from "@pie/platform";
import { resolveToCwd, type PathResolutionOptions } from "./path-utils.js";
import { DEFAULT_MAX_BYTES, formatSize, type TruncationResult, truncateHead } from "./truncate.js";

const lsSchema = Type.Object({
	path: Type.Optional(Type.String({ description: "Directory to list (default: workspace root). Example: 'Scripts' or 'Data'." })),
	limit: Type.Optional(Type.Number({ description: "Maximum number of entries to return (default: 500)." })),
});

export type LsToolInput = Static<typeof lsSchema>;

const DEFAULT_LIMIT = 500;

export interface LsToolDetails {
	truncation?: TruncationResult;
	entryLimitReached?: number;
}

export function createLsTool(
	cwd: string,
	options?: PathResolutionOptions,
): AgentTool<typeof lsSchema> {
	const fs = getFileSystem();

	return {
		name: "ls",
		label: "ls",
		description: `List directory contents. Use this to inspect folders before reading or writing files. Example: list_directory path='Scripts' or list_directory path='Data'. Returns entries sorted alphabetically, with '/' suffix for directories. Includes dotfiles. Output is truncated to ${DEFAULT_LIMIT} entries or ${DEFAULT_MAX_BYTES / 1024}KB (whichever is hit first).`,
		parameters: lsSchema,
		execute: async (
			_toolCallId: string,
			params: any,
			signal?: AbortSignal,
		) => {
			return new Promise((resolve, reject) => {
				if (signal?.aborted) {
					reject(new Error("Operation aborted"));
					return;
				}

				const onAbort = () => reject(new Error("Operation aborted"));
				signal?.addEventListener("abort", onAbort, { once: true });

				(async () => {
					try {
						const { path: dirPath, limit } = params;
						const targetPath = resolveToCwd(dirPath || ".", cwd, options);
						const effectiveLimit = limit ?? DEFAULT_LIMIT;

						if (!(await fs.exists(targetPath))) {
							reject(new Error(`Path not found: ${targetPath}`));
							return;
						}

						const stat = await fs.stat(targetPath);
						if (!stat.isDirectory) {
							reject(new Error(`Not a directory: ${targetPath}`));
							return;
						}

						let entries: string[];
						try {
							entries = await fs.readdir(targetPath);
						} catch (e: any) {
							reject(new Error(`Cannot read directory: ${e.message}`));
							return;
						}

						// Sort alphabetically (case-insensitive)
						entries.sort((a, b) => a.toLowerCase().localeCompare(b.toLowerCase()));

						const results: string[] = [];
						let entryLimitReached = false;

						for (const entry of entries) {
							if (results.length >= effectiveLimit) {
								entryLimitReached = true;
								break;
							}

							const fullPath = fs.join(targetPath, entry);
							let suffix = "";

							try {
								const entryStat = await fs.stat(fullPath);
								if (entryStat.isDirectory) {
									suffix = "/";
								}
							} catch {
								continue;
							}

							results.push(entry + suffix);
						}

						signal?.removeEventListener("abort", onAbort);

						if (results.length === 0) {
							resolve({ content: [{ type: "text", text: "(empty directory)" }], details: undefined, isError: true });
							return;
						}

						const rawOutput = results.join("\n");
						const truncation = truncateHead(rawOutput, { maxLines: Number.MAX_SAFE_INTEGER });

						let output = truncation.content;
						const details: LsToolDetails = {};

						const notices: string[] = [];

						if (entryLimitReached) {
							notices.push(`${effectiveLimit} entries limit reached. Use limit=${effectiveLimit * 2} for more`);
							details.entryLimitReached = effectiveLimit;
						}

						if (truncation.truncated) {
							notices.push(`${formatSize(DEFAULT_MAX_BYTES)} limit reached`);
							details.truncation = truncation;
						}

						if (notices.length > 0) {
							output += `\n\n[${notices.join(". ")}]`;
						}

						resolve({
							content: [{ type: "text", text: output }],
							details: Object.keys(details).length > 0 ? details : undefined,
						});
					} catch (e: any) {
						signal?.removeEventListener("abort", onAbort);
						reject(e);
					}
				})();
			});
		},
	};
}
