import type { AgentMessage } from "@pie/agent-core";

declare const CS: any;

export interface SessionSummary {
  id: string;
  title: string;
  createdAt: string;
  updatedAt: string;
  parentSessionId?: string;
  provider: string;
  modelId: string;
  messageCount: number;
}

export interface SessionRecord extends SessionSummary {
  messages: AgentMessage[];
  todoState: any[];
}

function getSessionsDir(projectRoot: string): string {
  const fromBridge = (globalThis as any).pieBridge?.getSessionsDirectory?.();
  if (typeof fromBridge === "string" && fromBridge.length > 0) {
    return fromBridge;
  }
  throw new Error("Pie session storage path is unavailable. pieBridge.getSessionsDirectory() must be provided by the host.");
}

function ensureSessionsDir(projectRoot: string): string {
  const dir = getSessionsDir(projectRoot);
  if (!CS.System.IO.Directory.Exists(dir)) {
    CS.System.IO.Directory.CreateDirectory(dir);
  }
  return dir;
}

function getSessionPath(projectRoot: string, sessionId: string): string {
  return CS.System.IO.Path.Combine(getSessionsDir(projectRoot), `${sessionId}.json`);
}

function isoNow(): string {
  return new Date().toISOString();
}

function createSessionId(): string {
  return `sess_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 8)}`;
}

function deriveTitle(messages: AgentMessage[]): string {
  const firstUser = messages.find((message: any) => message?.role === "user");
  if (!firstUser) return "New Session";

  const content = Array.isArray((firstUser as any).content)
    ? (firstUser as any).content
        .filter((block: any) => block?.type === "text")
        .map((block: any) => block.text || "")
        .join(" ")
    : "";
  const compact = String(content || "New Session").replace(/\s+/g, " ").trim();
  return compact.slice(0, 48) || "New Session";
}

function listSessionFiles(projectRoot: string): string[] {
  const dir = ensureSessionsDir(projectRoot);
  const files = CS.System.IO.Directory.GetFiles(dir, "*.json");
  const result: string[] = [];
  for (let i = 0; i < files.Length; i++) {
    result.push(files[i]);
  }
  return result;
}

export function createSessionRecord(params: {
  sessionId?: string;
  parentSessionId?: string;
  provider: string;
  modelId: string;
  messages: AgentMessage[];
  todoState: any[];
}): SessionRecord {
  const now = isoNow();
  return {
    id: params.sessionId || createSessionId(),
    title: deriveTitle(params.messages),
    createdAt: now,
    updatedAt: now,
    parentSessionId: params.parentSessionId,
    provider: params.provider,
    modelId: params.modelId,
    messageCount: params.messages.length,
    messages: params.messages,
    todoState: params.todoState,
  };
}

export function saveSession(projectRoot: string, record: SessionRecord): SessionRecord {
  ensureSessionsDir(projectRoot);

  let createdAt = record.createdAt;
  const existing = loadSession(projectRoot, record.id);
  if (existing?.createdAt) {
    createdAt = existing.createdAt;
  }

  const normalized: SessionRecord = {
    ...record,
    createdAt,
    updatedAt: isoNow(),
    title: deriveTitle(record.messages),
    messageCount: record.messages.length,
  };

  CS.System.IO.File.WriteAllText(
    getSessionPath(projectRoot, normalized.id),
    JSON.stringify(normalized, null, 2),
  );

  return normalized;
}

export function loadSession(projectRoot: string, sessionId: string): SessionRecord | null {
  const path = getSessionPath(projectRoot, sessionId);
  if (!CS.System.IO.File.Exists(path)) return null;
  try {
    return JSON.parse(CS.System.IO.File.ReadAllText(path)) as SessionRecord;
  } catch {
    return null;
  }
}

export function listSessions(projectRoot: string): SessionSummary[] {
  const sessions: SessionSummary[] = [];
  for (const path of listSessionFiles(projectRoot)) {
    try {
      const session = JSON.parse(CS.System.IO.File.ReadAllText(path)) as SessionRecord;
      sessions.push({
        id: session.id,
        title: session.title,
        createdAt: session.createdAt,
        updatedAt: session.updatedAt,
        parentSessionId: session.parentSessionId,
        provider: session.provider,
        modelId: session.modelId,
        messageCount: session.messageCount,
      });
    } catch {
      // Ignore malformed files for now
    }
  }

  sessions.sort((a, b) => String(b.updatedAt).localeCompare(String(a.updatedAt)));
  return sessions;
}

export function formatSessionTree(projectRoot: string): string {
  const sessions = listSessions(projectRoot);
  if (sessions.length === 0) return "No saved sessions.";

  const children = new Map<string, SessionSummary[]>();
  const roots: SessionSummary[] = [];

  for (const session of sessions) {
    if (!session.parentSessionId) {
      roots.push(session);
      continue;
    }
    const bucket = children.get(session.parentSessionId) || [];
    bucket.push(session);
    children.set(session.parentSessionId, bucket);
  }

  const lines: string[] = [];
  function render(node: SessionSummary, depth: number) {
    const indent = "  ".repeat(depth);
    lines.push(`${indent}- ${node.id} | ${node.title} | ${node.modelId} | ${node.updatedAt}`);
    const childSessions = children.get(node.id) || [];
    childSessions.sort((a, b) => String(b.updatedAt).localeCompare(String(a.updatedAt)));
    for (const child of childSessions) render(child, depth + 1);
  }

  roots.sort((a, b) => String(b.updatedAt).localeCompare(String(a.updatedAt)));
  for (const root of roots) render(root, 0);

  return lines.join("\n");
}
