/**
 * OpenAI-compatible provider using fetch() directly (no openai SDK).
 */

import { getEnvApiKey } from "../env-api-keys.js";
import { calculateCost } from "../models.js";
import type {
	AssistantMessage,
	AssistantMessageStream,
	Context,
	FileReferenceContent,
	Message,
	Model,
	OpenAICompletionsCompat,
	SimpleStreamOptions,
	StopReason,
	StreamFunction,
	StreamOptions,
	TextContent,
	ThinkingContent,
	Tool,
	ToolCall,
	ToolResultMessage,
	UserContentBlock,
	VideoContent,
} from "../types.js";
import { AssistantMessageEventStream } from "../utils/event-stream.js";
import { httpRequest } from "../utils/http.js";
import { parseStreamingJson } from "../utils/json-parse.js";
import { buildBaseOptions, clampReasoning } from "./simple-options.js";
import { transformMessages } from "./transform-messages.js";

// ─── Options ──────────────────────────────────────────────────────────────────

export interface OpenAICompletionsOptions extends StreamOptions {
	toolChoice?: "auto" | "none" | "required" | { type: "function"; function: { name: string } };
	reasoningEffort?: "minimal" | "low" | "medium" | "high" | "xhigh";
}

// ─── Stream function (low-level) ─────────────────────────────────────────────

export const streamOpenAICompletions: StreamFunction<"openai-completions", OpenAICompletionsOptions> = (
	model: Model<"openai-completions">,
	context: Context,
	options?: OpenAICompletionsOptions,
): AssistantMessageEventStream => {
	const stream = new AssistantMessageEventStream();

	(async () => {
		const output: AssistantMessage = {
			role: "assistant",
			content: [],
			api: model.api,
			provider: model.provider,
			model: model.id,
			usage: {
				input: 0,
				output: 0,
				cacheRead: 0,
				cacheWrite: 0,
				totalTokens: 0,
				cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0, total: 0 },
			},
			stopReason: "stop",
			timestamp: Date.now(),
		};

		try {
			const apiKey = options?.apiKey || getEnvApiKey(model.provider) || "";
			if (!apiKey) {
				throw new Error(`No API key for provider: ${model.provider}`);
			}

			const compat = getCompat(model);
			const params = buildParams(model, context, options, compat);
			options?.onPayload?.(params);

			// HTTP request using Node.js native https module
			const headers: Record<string, string> = {
				"Content-Type": "application/json",
				Authorization: `Bearer ${apiKey}`,
				// GLM/bigmodel requires specific accept header for SSE
				...(model.provider === "bigmodel" ? { "Accept": "text/event-stream" } : {}),
				...(model.headers || {}),
				...(options?.headers || {}),
			};

			const response = await httpRequest(`${model.baseUrl}/chat/completions`, {
				method: "POST",
				headers,
				body: JSON.stringify(params),
				signal: options?.signal,
			});

			if (!response.ok) {
				const errorBody = await response.text().catch(() => "");
				throw new Error(`API error ${response.status}: ${errorBody}`);
			}

			stream.push({ type: "start", partial: output });

			// Parse SSE stream using Node.js native http response
			let currentBlock: TextContent | ThinkingContent | (ToolCall & { partialArgs?: string }) | null =
				null;
			const blocks = output.content;
			const blockIndex = () => blocks.length - 1;

			const finishCurrentBlock = (block?: typeof currentBlock) => {
				if (block) {
					if (block.type === "text") {
						stream.push({
							type: "text_end",
							contentIndex: blockIndex(),
							content: block.text,
							partial: output,
						});
					} else if (block.type === "thinking") {
						stream.push({
							type: "thinking_end",
							contentIndex: blockIndex(),
							content: block.thinking,
							partial: output,
						});
					} else if (block.type === "toolCall") {
						block.arguments = parseStreamingJson(block.partialArgs);
						delete (block as any).partialArgs;
						stream.push({
							type: "toolcall_end",
							contentIndex: blockIndex(),
							toolCall: block,
							partial: output,
						});
					}
				}
			};

			if (!response.readSSELines) {
				throw new Error('SSE streaming not supported on this platform');
			}

			for await (const line of response.readSSELines!(options?.signal)) {
				{
					const trimmed = line.trim();
					if (!trimmed || trimmed.startsWith(":")) continue;

					if (trimmed.startsWith("data: ")) {
						const data = trimmed.slice(6);
						if (data === "[DONE]") continue;

						let chunk: any;
						try {
							chunk = JSON.parse(data);
						} catch {
							continue;
						}

						// Process usage
						if (chunk.usage) {
							const cachedTokens = chunk.usage.prompt_tokens_details?.cached_tokens || 0;
							const reasoningTokens =
								chunk.usage.completion_tokens_details?.reasoning_tokens || 0;
							const input = (chunk.usage.prompt_tokens || 0) - cachedTokens;
							const outputTokens = (chunk.usage.completion_tokens || 0) + reasoningTokens;
							output.usage = {
								input,
								output: outputTokens,
								cacheRead: cachedTokens,
								cacheWrite: 0,
								totalTokens: input + outputTokens + cachedTokens,
								cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0, total: 0 },
							};
							calculateCost(model, output.usage);

							// Debug: log cache usage
							if (process.env.PIE_DEBUG_CACHE) {
								console.error("[CACHE DEBUG] Response usage:", JSON.stringify({
									input_tokens: input,
									output_tokens: outputTokens,
									cached_tokens: cachedTokens,
									cache_hit_rate: chunk.usage.prompt_tokens ? 
										`${((cachedTokens / chunk.usage.prompt_tokens) * 100).toFixed(1)}%` : 'N/A',
								}, null, 2));
							}
						}

						const choice = chunk.choices?.[0];
						if (!choice) continue;

						if (choice.finish_reason) {
							output.stopReason = mapStopReason(choice.finish_reason);
						}

						if (choice.delta) {
							// Text content
							if (
								choice.delta.content !== null &&
								choice.delta.content !== undefined &&
								choice.delta.content.length > 0
							) {
								if (!currentBlock || currentBlock.type !== "text") {
									finishCurrentBlock(currentBlock);
									currentBlock = { type: "text", text: "" };
									output.content.push(currentBlock);
									stream.push({
										type: "text_start",
										contentIndex: blockIndex(),
										partial: output,
									});
								}

								if (currentBlock.type === "text") {
									currentBlock.text += choice.delta.content;
									stream.push({
										type: "text_delta",
										contentIndex: blockIndex(),
										delta: choice.delta.content,
										partial: output,
									});
								}
							}

							// Reasoning / thinking content
							const reasoningFields = [
								"reasoning_content",
								"reasoning",
								"reasoning_text",
							];
							let foundReasoningField: string | null = null;
							for (const field of reasoningFields) {
								if (
									choice.delta[field] !== null &&
									choice.delta[field] !== undefined &&
									choice.delta[field].length > 0
								) {
									foundReasoningField = field;
									break;
								}
							}

							if (foundReasoningField) {
								if (!currentBlock || currentBlock.type !== "thinking") {
									finishCurrentBlock(currentBlock);
									currentBlock = {
										type: "thinking",
										thinking: "",
										thinkingSignature: foundReasoningField,
									};
									output.content.push(currentBlock);
									stream.push({
										type: "thinking_start",
										contentIndex: blockIndex(),
										partial: output,
									});
								}

								if (currentBlock.type === "thinking") {
									const delta = choice.delta[foundReasoningField];
									currentBlock.thinking += delta;
									stream.push({
										type: "thinking_delta",
										contentIndex: blockIndex(),
										delta,
										partial: output,
									});
								}
							}

							// Tool calls
							if (choice.delta.tool_calls) {
								for (const toolCall of choice.delta.tool_calls) {
									if (
										!currentBlock ||
										currentBlock.type !== "toolCall" ||
										(toolCall.id && currentBlock.id !== toolCall.id)
									) {
										finishCurrentBlock(currentBlock);
										currentBlock = {
											type: "toolCall",
											id: toolCall.id || "",
											name: toolCall.function?.name || "",
											arguments: {},
											partialArgs: "",
										};
										output.content.push(currentBlock);
										stream.push({
											type: "toolcall_start",
											contentIndex: blockIndex(),
											partial: output,
										});
									}

									if (currentBlock.type === "toolCall") {
										if (toolCall.id) currentBlock.id = toolCall.id;
										if (toolCall.function?.name)
											currentBlock.name = toolCall.function.name;
										let delta = "";
										if (toolCall.function?.arguments) {
											delta = toolCall.function.arguments;
											(currentBlock as any).partialArgs +=
												toolCall.function.arguments;
											currentBlock.arguments = parseStreamingJson(
												(currentBlock as any).partialArgs,
											);
										}
										stream.push({
											type: "toolcall_delta",
											contentIndex: blockIndex(),
											delta,
											partial: output,
										});
									}
								}
							}
						}
					}
				}
			}

			finishCurrentBlock(currentBlock);

			if (options?.signal?.aborted) {
				throw new Error("Request was aborted");
			}

			if (output.stopReason === "aborted" || output.stopReason === "error") {
				throw new Error("An unknown error occurred");
			}

			stream.push({ type: "done", reason: output.stopReason, message: output });
			stream.end();
		} catch (error) {
			output.stopReason = options?.signal?.aborted ? "aborted" : "error";
			output.errorMessage = error instanceof Error ? error.message : JSON.stringify(error);
			stream.push({ type: "error", reason: output.stopReason, error: output });
			stream.end();
		}
	})();

	return stream;
};

// ─── streamSimple (unified reasoning interface) ──────────────────────────────

export const streamSimpleOpenAICompletions: StreamFunction<"openai-completions", SimpleStreamOptions> = (
	model: Model<"openai-completions">,
	context: Context,
	options?: SimpleStreamOptions,
): AssistantMessageStream => {
	const apiKey = options?.apiKey || getEnvApiKey(model.provider);
	if (!apiKey) {
		throw new Error(`No API key for provider: ${model.provider}`);
	}

	const base = buildBaseOptions(model, options, apiKey);
	const reasoningEffort = clampReasoning(options?.reasoning);

	return streamOpenAICompletions(model, context, {
		...base,
		reasoningEffort,
	} satisfies OpenAICompletionsOptions);
};

// ─── Message conversion (to OpenAI Chat Completions format) ──────────────────

interface ChatCompletionMessage {
	role: string;
	content: any;
	tool_calls?: any[];
	tool_call_id?: string;
	name?: string;
}

function buildParams(
	model: Model<"openai-completions">,
	context: Context,
	options: OpenAICompletionsOptions | undefined,
	compat: Required<OpenAICompletionsCompat>,
) {
	const messages = convertMessages(model, context, compat);

	const params: Record<string, any> = {
		model: model.id,
		messages,
		stream: true,
	};

	if (compat.supportsUsageInStreaming !== false) {
		params.stream_options = { include_usage: true };
	}

	if (compat.supportsStore) {
		// Enable conversation storage based on cache retention policy
		params.store = options?.cacheRetention !== "none";
	}

	// Pass session ID if provided (used by some providers for conversation continuity)
	if (options?.sessionId && compat.supportsStore) {
		params.session_id = options.sessionId;
	}

	// Debug: log cache parameters
	if (process.env.PIE_DEBUG_CACHE) {
		console.error("[CACHE DEBUG] Request params:", JSON.stringify({
			model: params.model,
			store: params.store,
			session_id: params.session_id,
			cacheRetention: options?.cacheRetention,
			supportsStore: compat.supportsStore,
			provider: model.provider,
		}, null, 2));
	}

	if (options?.maxTokens) {
		if (compat.maxTokensField === "max_tokens") {
			params.max_tokens = options.maxTokens;
		} else {
			params.max_completion_tokens = options.maxTokens;
		}
	}

	if (options?.temperature !== undefined) {
		params.temperature = options.temperature;
	}

	if (context.tools) {
		params.tools = convertTools(context.tools, compat);
	}

	if (options?.toolChoice) {
		params.tool_choice = options.toolChoice;
	}

	if (options?.reasoningEffort && model.reasoning && compat.supportsReasoningEffort) {
		params.reasoning_effort = options.reasoningEffort;
	}

	return params;
}

function convertMessages(
	model: Model<"openai-completions">,
	context: Context,
	compat: Required<OpenAICompletionsCompat>,
): ChatCompletionMessage[] {
	const params: ChatCompletionMessage[] = [];

	const normalizeToolCallId = (id: string): string => {
		return id.length > 40 ? id.slice(0, 40) : id;
	};

	const transformedMessages = transformMessages(context.messages, model, (id) => normalizeToolCallId(id));

	if (context.systemPrompt) {
		const useDeveloperRole = model.reasoning && compat.supportsDeveloperRole;
		const role = useDeveloperRole ? "developer" : "system";
		params.push({ role, content: context.systemPrompt });
	}

	for (let i = 0; i < transformedMessages.length; i++) {
		const msg = transformedMessages[i];

		if (msg.role === "user") {
			if (typeof msg.content === "string") {
				params.push({ role: "user", content: msg.content });
			} else {
				const content = msg.content.flatMap((item) => convertUserContentItem(item));
				const filteredContent = content.filter((c: any) => {
					if (c.type === "text") return true;
					if (c.type === "image_url") return model.input.includes("image");
					if (c.type === "video_url") return model.input.includes("video");
					return true;
				});
				if (filteredContent.length === 0) continue;
				params.push({ role: "user", content: filteredContent });
			}
		} else if (msg.role === "assistant") {
			const assistantMsg: ChatCompletionMessage = {
				role: "assistant",
				content: null,
			};

			const textBlocks = msg.content.filter((b) => b.type === "text") as TextContent[];
			const nonEmptyTextBlocks = textBlocks.filter((b) => b.text && b.text.trim().length > 0);
			if (nonEmptyTextBlocks.length > 0) {
				assistantMsg.content = nonEmptyTextBlocks.map((b) => ({
					type: "text",
					text: b.text,
				}));
			}

			// Handle thinking blocks
			const thinkingBlocks = msg.content.filter((b) => b.type === "thinking") as ThinkingContent[];
			const nonEmptyThinkingBlocks = thinkingBlocks.filter(
				(b) => b.thinking && b.thinking.trim().length > 0,
			);
			if (nonEmptyThinkingBlocks.length > 0) {
				if (compat.requiresThinkingAsText) {
					const thinkingText = nonEmptyThinkingBlocks.map((b) => b.thinking).join("\n\n");
					const textContent = assistantMsg.content as Array<{ type: string; text: string }> | null;
					if (textContent) {
						textContent.unshift({ type: "text", text: thinkingText });
					} else {
						assistantMsg.content = [{ type: "text", text: thinkingText }];
					}
				} else {
					const signature = nonEmptyThinkingBlocks[0].thinkingSignature;
					if (signature && signature.length > 0) {
						(assistantMsg as any)[signature] = nonEmptyThinkingBlocks
							.map((b) => b.thinking)
							.join("\n");
					}
				}
			}

			const toolCalls = msg.content.filter((b) => b.type === "toolCall") as ToolCall[];
			if (toolCalls.length > 0) {
				assistantMsg.tool_calls = toolCalls.map((tc) => ({
					id: tc.id,
					type: "function",
					function: {
						name: tc.name,
						arguments: JSON.stringify(tc.arguments),
					},
				}));
				
				// Kimi K2.5 requires reasoning_content when tool calls are present and thinking is enabled
				if (!compat.requiresThinkingAsText && !(assistantMsg as any).reasoning_content) {
					(assistantMsg as any).reasoning_content = "";
				}
			}

			const content = assistantMsg.content;
			const hasContent =
				content !== null &&
				content !== undefined &&
				(typeof content === "string" ? content.length > 0 : content.length > 0);
			if (!hasContent && !assistantMsg.tool_calls) {
				continue;
			}

			params.push(assistantMsg);
		} else if (msg.role === "toolResult") {
			for (; i < transformedMessages.length && transformedMessages[i].role === "toolResult"; i++) {
				const toolMsg = transformedMessages[i] as ToolResultMessage;
				const textResult = toolMsg.content
					.filter((c) => c.type === "text")
					.map((c) => (c as TextContent).text)
					.join("\n");

				const toolResultMsg: ChatCompletionMessage = {
					role: "tool",
					content: textResult || "(empty result)",
					tool_call_id: toolMsg.toolCallId,
				};

				if (compat.requiresToolResultName && toolMsg.toolName) {
					toolResultMsg.name = toolMsg.toolName;
				}

				params.push(toolResultMsg);
			}
			i--; // Adjust for outer loop increment
		}
	}

	return params;
}

function convertUserContentItem(item: UserContentBlock): Array<Record<string, unknown>> {
	if (item.type === "text") {
		return [{ type: "text", text: item.text }];
	}

	if (item.type === "image") {
		return [{
			type: "image_url",
			image_url: { url: `data:${item.mimeType};base64,${item.data}` },
		}];
	}

	if (item.type === "video") {
		const video = item as VideoContent;
		return [{
			type: "video_url",
			video_url: { url: `data:${video.mimeType};base64,${video.data}` },
		}];
	}

	if (item.type === "fileRef") {
		const ref = item as FileReferenceContent;
		if (ref.modality === "image") {
			return [{ type: "image_url", image_url: { url: ref.url } }];
		}
		if (ref.modality === "video") {
			return [{ type: "video_url", video_url: { url: ref.url } }];
		}
		return [{ type: "file", file_url: { url: ref.url } }];
	}

	return [];
}

function convertTools(tools: Tool[], compat: Required<OpenAICompletionsCompat>) {
	return tools.map((tool) => ({
		type: "function",
		function: {
			name: tool.name,
			description: tool.description,
			parameters: tool.parameters as any,
			...(compat.supportsStrictMode !== false && { strict: false }),
		},
	}));
}

function mapStopReason(reason: string | null): StopReason {
	if (reason === null) return "stop";
	switch (reason) {
		case "stop":
			return "stop";
		case "length":
			return "length";
		case "function_call":
		case "tool_calls":
			return "toolUse";
		case "content_filter":
			return "error";
		default:
			return "stop";
	}
}

// ─── Compat detection ────────────────────────────────────────────────────────

function detectCompat(model: Model<"openai-completions">): Required<OpenAICompletionsCompat> {
	const isMoonshot =
		model.provider === "kimi-cn" ||
		model.baseUrl.includes("moonshot.cn") ||
		model.baseUrl.includes("moonshot.ai");

	return {
		// Moonshot/Kimi supports conversation storage for context caching
		supportsStore: isMoonshot,
		supportsDeveloperRole: false,
		supportsReasoningEffort: false,
		supportsUsageInStreaming: true,
		maxTokensField: "max_tokens",
		requiresToolResultName: false,
		requiresAssistantAfterToolResult: false,
		// Kimi K2.5 returns reasoning_content and requires it replayed as-is
		requiresThinkingAsText: !isMoonshot,
		supportsStrictMode: true,
	};
}

function getCompat(model: Model<"openai-completions">): Required<OpenAICompletionsCompat> {
	const detected = detectCompat(model);
	if (!model.compat) return detected;

	return {
		supportsStore: model.compat.supportsStore ?? detected.supportsStore,
		supportsDeveloperRole: model.compat.supportsDeveloperRole ?? detected.supportsDeveloperRole,
		supportsReasoningEffort: model.compat.supportsReasoningEffort ?? detected.supportsReasoningEffort,
		supportsUsageInStreaming: model.compat.supportsUsageInStreaming ?? detected.supportsUsageInStreaming,
		maxTokensField: model.compat.maxTokensField ?? detected.maxTokensField,
		requiresToolResultName: model.compat.requiresToolResultName ?? detected.requiresToolResultName,
		requiresAssistantAfterToolResult:
			model.compat.requiresAssistantAfterToolResult ?? detected.requiresAssistantAfterToolResult,
		requiresThinkingAsText: model.compat.requiresThinkingAsText ?? detected.requiresThinkingAsText,
		supportsStrictMode: model.compat.supportsStrictMode ?? detected.supportsStrictMode,
	};
}
