/**
 * Find tool - Search for files by glob pattern.
 */

import type { AgentTool } from "@pie/agent-core";
import type { Static } from "@sinclair/typebox";
import { Type } from "@sinclair/typebox";
import { getFileSystem, detectPlatform } from "@pie/platform";
import { resolveToCwd, type PathResolutionOptions } from "./path-utils.js";
import { DEFAULT_MAX_BYTES, formatSize, type TruncationResult, truncateHead } from "./truncate.js";

const findSchema = Type.Object({
	pattern: Type.String({
		description: "Glob pattern to match files, e.g. '*.ts', '**/*.json', or 'src/**/*.spec.ts'",
	}),
	path: Type.Optional(Type.String({ description: "Directory to search in (default: sandbox root)" })),
	limit: Type.Optional(Type.Number({ description: "Maximum number of results (default: 1000)" })),
});

export type FindToolInput = Static<typeof findSchema>;

const DEFAULT_LIMIT = 1000;

declare const CS: any;

export interface FindToolDetails {
	truncation?: TruncationResult;
	resultLimitReached?: number;
}

// Directories to skip
const SKIP_DIRS = new Set(["node_modules", ".git", "__pycache__", ".svn", ".hg"]);

/**
 * Convert a glob pattern to a regex pattern
 */
function globToRegex(pattern: string): RegExp {
	// Escape special regex characters except glob wildcards
	let regexPattern = pattern
		.replace(/\*\*/g, "__GLOBSTAR__")
		.replace(/\*/g, "__STAR__")
		.replace(/\?/g, "__QMARK__")
		.replace(/[.+^${}()|[\]\\]/g, "\\$&")
		.replace(/__GLOBSTAR__/g, ".*")
		.replace(/__STAR__/g, "[^/]*")
		.replace(/__QMARK__/g, ".");

	// Handle directory separators for cross-platform
	regexPattern = regexPattern.replace(/\//g, "[/\\\\]");

	return new RegExp("^" + regexPattern + "$", "i");
}

/**
 * Check if a path matches a glob pattern
 */
function matchesGlob(filePath: string, pattern: string): boolean {
	const regex = globToRegex(pattern);
	return regex.test(filePath);
}

function getNativeFileBridge(): any | null {
	try {
		return typeof CS !== "undefined" && CS?.Pie?.PieFileBridge ? CS.Pie.PieFileBridge : null;
	} catch {
		return null;
	}
}

type FileCompletionRecord = { resultJson: string | null; error: string | null };
type FileCompletionStore = {
	completions: Map<number, FileCompletionRecord>;
	waiters: Map<number, (value: FileCompletionRecord) => void>;
};

function getFileCompletionStore(): FileCompletionStore {
	const g = globalThis as any;
	if (!g.__pieFileCompletionStore) {
		g.__pieFileCompletionStore = {
			completions: new Map<number, FileCompletionRecord>(),
			waiters: new Map<number, (value: FileCompletionRecord) => void>(),
		};
	}

	if (!g._pieFileComplete) {
		g._pieFileComplete = (requestId: number, resultJson: string | null, error: string | null) => {
			const store = getFileCompletionStore();
			const payload = { resultJson, error };
			store.completions.set(requestId, payload);
			const waiter = store.waiters.get(requestId);
			if (waiter) {
				store.waiters.delete(requestId);
				waiter(payload);
			}
		};
	}

	return g.__pieFileCompletionStore as FileCompletionStore;
}

function waitForFileCompletion(requestId: number): Promise<FileCompletionRecord> {
	const store = getFileCompletionStore();
	const existing = store.completions.get(requestId);
	if (existing) {
		return Promise.resolve(existing);
	}

	return new Promise<FileCompletionRecord>((resolve) => {
		store.waiters.set(requestId, resolve);
	});
}

interface NativeFindResult {
	Results?: string[];
	ScannedDirectories?: number;
	ScannedFiles?: number;
	LimitReached?: boolean;
}

async function runNativeFind(
	searchPath: string,
	pattern: string,
	limit: number,
	signal?: AbortSignal,
): Promise<NativeFindResult> {
	const bridge = getNativeFileBridge();
	if (!bridge) {
		throw new Error("CS.Pie.PieFileBridge not available");
	}

	const requestId = bridge.StartFind(searchPath, pattern, limit);
	const onAbort = () => bridge.CancelRequest(requestId);
	signal?.addEventListener("abort", onAbort, { once: true });

	try {
		if (signal?.aborted) {
			bridge.CancelRequest(requestId);
			throw new Error("Operation aborted");
		}

		const completion = await waitForFileCompletion(requestId);
		if (completion.error) {
			throw new Error(completion.error);
		}

		if (!completion.resultJson) {
			return {};
		}

		return JSON.parse(completion.resultJson) as NativeFindResult;
	} finally {
		const store = getFileCompletionStore();
		store.completions.delete(requestId);
		store.waiters.delete(requestId);
		signal?.removeEventListener("abort", onAbort);
		bridge.ReleaseRequest(requestId);
	}
}

/**
 * Recursively collect all files matching a glob pattern
 */
async function globFiles(
	rootPath: string,
	pattern: string,
	fs: any,
	limit: number,
	signal?: AbortSignal
): Promise<string[]> {
	const results: string[] = [];
	const queue: Array<{ dir: string; relPrefix: string }> = [{ dir: rootPath, relPrefix: "" }];

	while (queue.length > 0 && results.length < limit) {
		if (signal?.aborted) {
			throw new Error("Operation aborted");
		}

		const { dir, relPrefix } = queue.shift()!;

		let entries: string[];
		try {
			entries = await fs.readdir(dir);
		} catch {
			continue;
		}

		for (const entry of entries) {
			if (results.length >= limit) break;

			const fullPath = fs.join(dir, entry);
			const relPath = relPrefix ? relPrefix + "/" + entry : entry;

			let stat: any;
			try {
				stat = await fs.stat(fullPath);
			} catch {
				continue;
			}

			if (stat.isDirectory) {
				if (SKIP_DIRS.has(entry)) continue;
				queue.push({ dir: fullPath, relPrefix: relPath });
			} else if (stat.isFile) {
				// Check if file matches pattern
				if (matchesGlob(relPath, pattern) || matchesGlob(entry, pattern)) {
					results.push(relPath);
				}
			}
		}
	}

	return results;
}

export function createFindTool(
	cwd: string,
	options?: PathResolutionOptions,
): AgentTool<typeof findSchema> {
	const fs = getFileSystem();
	const platform = detectPlatform();

	return {
		name: "find",
		label: "find",
		description: `Search for files by glob pattern. Returns matching file paths relative to the search directory. Output is truncated to ${DEFAULT_LIMIT} results or ${DEFAULT_MAX_BYTES / 1024}KB (whichever is hit first).`,
		parameters: findSchema,
		execute: async (
			_toolCallId: string,
			{ pattern, path: searchDir, limit }: { pattern: string; path?: string; limit?: number },
			signal?: AbortSignal,
		) => {
			return new Promise((resolve, reject) => {
				if (signal?.aborted) {
					reject(new Error("Operation aborted"));
					return;
				}

				const onAbort = () => reject(new Error("Operation aborted"));
				signal?.addEventListener("abort", onAbort, { once: true });

				(async () => {
					try {
						const searchPath = resolveToCwd(searchDir || ".", cwd, options);
						const effectiveLimit = limit ?? DEFAULT_LIMIT;

						if (!(await fs.exists(searchPath))) {
							reject(new Error(`Path not found: ${searchPath}`));
							return;
						}

						let results: string[];

						if (platform === "puerts" && getNativeFileBridge()) {
							const nativeResult = await runNativeFind(searchPath, pattern, effectiveLimit, signal);
							results = nativeResult.Results ?? [];
							(globalThis as any).pieBridge?.log?.(
								"info",
								`[find] path=${searchPath} pattern=${pattern} matches=${results.length} dirs=${nativeResult.ScannedDirectories ?? 0} files=${nativeResult.ScannedFiles ?? 0}`,
							);
						} else if (platform === "node") {
							// In Node.js, try to use glob if available
							try {
								const _require = (globalThis as any).require || require;
								const { globSync } = _require("glob");
								results = globSync(pattern, {
									cwd: searchPath,
									ignore: ["**/node_modules/**", "**/.git/**"],
									nodir: false,
									absolute: false,
									dot: true,
								}).slice(0, effectiveLimit);
							} catch {
								// Fallback to native implementation
								results = await globFiles(searchPath, pattern, fs, effectiveLimit, signal);
							}
						} else {
							// In PuerTS, use native implementation
							results = await globFiles(searchPath, pattern, fs, effectiveLimit, signal);
						}

						signal?.removeEventListener("abort", onAbort);

						if (results.length === 0) {
							resolve({
								content: [{ type: "text", text: "No files found matching pattern" }],
								details: undefined,
								isError: true,
							});
							return;
						}

						const resultLimitReached = results.length >= effectiveLimit;
						const rawOutput = results.join("\n");
						const truncation = truncateHead(rawOutput, { maxLines: Number.MAX_SAFE_INTEGER });

						let resultOutput = truncation.content;
						const details: FindToolDetails = {};
						const notices: string[] = [];

						if (resultLimitReached) {
							notices.push(`${effectiveLimit} results limit reached`);
							details.resultLimitReached = effectiveLimit;
						}

						if (truncation.truncated) {
							notices.push(`${formatSize(DEFAULT_MAX_BYTES)} limit reached`);
							details.truncation = truncation;
						}

						if (notices.length > 0) {
							resultOutput += "\n\n[" + notices.join(". ") + "]";
						}

						resolve({
							content: [{ type: "text", text: resultOutput }],
							details: Object.keys(details).length > 0 ? details : undefined,
						});
					} catch (e: any) {
						signal?.removeEventListener("abort", onAbort);
						reject(e);
					}
				})();
			});
		},
	};
}
