import type { AgentTool } from "@pie/agent-core";
import type { Static } from "@sinclair/typebox";
import { Type } from "@sinclair/typebox";
import { resolveToCwd, type PathResolutionOptions } from "@pie/tools-fs";
import {
  DEFAULT_MAX_BYTES,
  formatSize,
  GREP_MAX_LINE_LENGTH,
  type TruncationResult,
  truncateHead,
} from "@pie/tools-fs";

declare const CS: any;
declare const puer: any;

const grepSchema = Type.Object({
  pattern: Type.String({ description: "The text or regex pattern to search for inside files. Example literal patterns: 'MonoBehaviour', 'Hello from Pie'. Example regex: 'class\\s+DemoScript'." }),
  path: Type.Optional(Type.String({ description: "Directory or file to search (default: workspace root). Example: 'Scripts' or 'Data/dialogue'." })),
  glob: Type.Optional(Type.String({ description: "Optional file filter, e.g. '*.cs', '*.json', or '**/*.txt'. Use this to narrow which files are searched." })),
  ignoreCase: Type.Optional(Type.Boolean({ description: "Case-insensitive search (default: false)" })),
  literal: Type.Optional(Type.Boolean({ description: "Treat pattern as plain text instead of regex (default: false). Use literal=true for normal substring searches like 'MonoBehaviour'." })),
  context: Type.Optional(Type.Number({ description: "Number of lines to show before and after each match (default: 0)" })),
  limit: Type.Optional(Type.Number({ description: "Maximum number of matches to return (default: 100)" })),
});

const DEFAULT_LIMIT = 100;

interface NativeGrepResult {
  Lines?: string[];
  MatchCount?: number;
  MatchLimitReached?: boolean;
  LinesTruncated?: boolean;
  FilesScanned?: number;
  Pattern?: string;
  SearchPath?: string;
  Glob?: string;
  Literal?: boolean;
  IgnoreCase?: boolean;
}

export interface NativeGrepToolDetails {
  truncation?: TruncationResult;
  matchLimitReached?: number;
  linesTruncated?: boolean;
  filesScanned?: number;
  effectivePattern?: string;
  searchPath?: string;
  glob?: string;
  literal?: boolean;
  ignoreCase?: boolean;
}

function awaitTask<T>(task: any): Promise<T> {
  if (!puer?.$promise) {
    throw new Error("puer.$promise is not available");
  }
  return puer.$promise(task) as Promise<T>;
}

export function createNativeGrepTool(
  cwd: string,
  options?: PathResolutionOptions,
): AgentTool<typeof grepSchema> {
  return {
    name: "grep",
    label: "grep",
    description: `Search inside file contents. Use this when you know some text that should appear in the file. Common usage: pattern='MonoBehaviour', glob='*.cs', literal=true. Prefer targeted folders like 'Scripts' or 'Data' over scanning the whole project. Returns matching lines with file paths and line numbers. Output is truncated to ${DEFAULT_LIMIT} matches or ${DEFAULT_MAX_BYTES / 1024}KB (whichever is hit first). Long lines are truncated to ${GREP_MAX_LINE_LENGTH} chars.`,
    parameters: grepSchema,
    execute: async (
      _toolCallId: string,
      { pattern, path: searchDir, glob, ignoreCase, literal, context, limit }: Static<typeof grepSchema>,
    ) => {
      const searchPath = resolveToCwd(searchDir || ".", cwd, options);
      const effectiveLimit = Math.max(1, limit ?? DEFAULT_LIMIT);
      const ctx = context && context > 0 ? context : 0;

      if ((globalThis as any).__pieVerboseLogs) {
        (globalThis as any).pieBridge?.log?.(
          "info",
          `[native grep] path=${searchPath} pattern=${pattern} glob=${glob ?? ""} limit=${effectiveLimit}`,
        );
      }

      const json = await awaitTask<string>(
        CS.Pie.PieFileBridge.GrepAsync(
          searchPath,
          pattern,
          glob ?? "",
          !!ignoreCase,
          !!literal,
          ctx,
          effectiveLimit,
        ),
      );

      const nativeResult = json ? (JSON.parse(json) as NativeGrepResult) : {};
      const outputLines = nativeResult.Lines ?? [];
      const matchCount = nativeResult.MatchCount ?? 0;

      if ((globalThis as any).__pieVerboseLogs) {
        (globalThis as any).pieBridge?.log?.(
          "info",
          `[native grep] done path=${searchPath} pattern=${pattern} matches=${matchCount} files=${nativeResult.FilesScanned ?? 0}`,
        );
      }

      if (matchCount === 0) {
        return {
          content: [{ type: "text" as const, text: "No matches found" }],
          details: {
            filesScanned: nativeResult.FilesScanned ?? 0,
            effectivePattern: nativeResult.Pattern ?? pattern,
            searchPath: nativeResult.SearchPath ?? searchPath,
            glob: nativeResult.Glob ?? glob,
            literal: nativeResult.Literal ?? !!literal,
            ignoreCase: nativeResult.IgnoreCase ?? !!ignoreCase,
          },
          isError: true,
        };
      }

      const rawOutput = outputLines.join("\n");
      const truncation = truncateHead(rawOutput, { maxLines: Number.MAX_SAFE_INTEGER });
      let output = truncation.content;
      const details: NativeGrepToolDetails = {
        filesScanned: nativeResult.FilesScanned,
        effectivePattern: nativeResult.Pattern ?? pattern,
        searchPath: nativeResult.SearchPath ?? searchPath,
        glob: nativeResult.Glob ?? glob,
        literal: nativeResult.Literal ?? !!literal,
        ignoreCase: nativeResult.IgnoreCase ?? !!ignoreCase,
      };
      const notices: string[] = [];

      if (nativeResult.MatchLimitReached) {
        notices.push(`${effectiveLimit} matches limit reached`);
        details.matchLimitReached = effectiveLimit;
      }

      if (truncation.truncated) {
        notices.push(`${formatSize(DEFAULT_MAX_BYTES)} limit reached`);
        details.truncation = truncation;
      }

      if (nativeResult.LinesTruncated) {
        notices.push(`lines longer than ${GREP_MAX_LINE_LENGTH} chars were truncated`);
        details.linesTruncated = true;
      }

      if (notices.length > 0) {
        output += `\n\n[${notices.join(". ")}]`;
      }

      return {
        content: [{ type: "text" as const, text: output }],
        details,
      };
    },
  };
}
