import type { AgentHooks, AgentTool } from "@pie/agent-core";
import { Type, type TSchema } from "@sinclair/typebox";

export interface PieExtensionContext {
  projectRoot: string;
  isEditor: boolean;
  log: (message: string) => void;
}

export interface PieExtensionApi extends PieExtensionContext {
  registerTool: (tool: AgentTool<any>) => void;
  registerBeforeToolCall: (hook: BeforeToolCallHook) => void;
  registerAfterToolCall: (hook: AfterToolCallHook) => void;
  registerOnError: (hook: OnErrorHook) => void;
  appendSystemPrompt: (text: string) => void;
  callHost: <T = any>(name: string, args?: any) => Promise<T>;
}

type BeforeToolCallHook = NonNullable<AgentHooks["beforeToolCall"]>;
type AfterToolCallHook = NonNullable<AgentHooks["afterToolCall"]>;
type OnErrorHook = NonNullable<AgentHooks["onError"]>;

const extensionTools: AgentTool<any>[] = [];
const beforeToolCallHooks: BeforeToolCallHook[] = [];
const afterToolCallHooks: AfterToolCallHook[] = [];
const onErrorHooks: OnErrorHook[] = [];
const systemPromptPatches: string[] = [];
const loadedExtensions: string[] = [];
const typeBoxKind = Symbol.for("TypeBox.Kind");

function isTypeBoxSchema(value: unknown): value is TSchema {
  return !!value && typeof value === "object" && typeBoxKind in (value as Record<PropertyKey, unknown>);
}

function convertJsonSchemaToTypeBox(schema: any): TSchema {
  if (!schema || typeof schema !== "object") {
    throw new Error("Tool parameters must be a TypeBox schema or a JSON schema object.");
  }

  if (isTypeBoxSchema(schema)) {
    return schema;
  }

  const description = typeof schema.description === "string" ? schema.description : undefined;
  const options = description ? { description } : undefined;

  switch (schema.type) {
    case "string":
      return Type.String(options);
    case "number":
      return Type.Number(options);
    case "integer":
      return Type.Integer(options);
    case "boolean":
      return Type.Boolean(options);
    case "null":
      return Type.Null(options);
    case "array":
      return Type.Array(convertJsonSchemaToTypeBox(schema.items ?? { type: "string" }), options);
    case "object": {
      const properties = schema.properties ?? {};
      const required = new Set<string>(Array.isArray(schema.required) ? schema.required : []);
      const converted: Record<string, TSchema> = {};

      for (const [key, value] of Object.entries(properties)) {
        const child = convertJsonSchemaToTypeBox(value);
        converted[key] = required.has(key) ? child : Type.Optional(child);
      }

      return Type.Object(converted, options);
    }
    default:
      throw new Error(`Unsupported JSON schema type for extension tool: ${String(schema.type ?? "unknown")}`);
  }
}

function extensionLog(context: PieExtensionContext, message: string) {
  context.log(`[extension] ${message}`);
}

function tryParseHostResult(raw: unknown): any {
  if (typeof raw !== "string") {
    return raw;
  }

  const trimmed = raw.trim();
  if (!trimmed) return "";

  const looksLikeJson =
    (trimmed.startsWith("{") && trimmed.endsWith("}")) ||
    (trimmed.startsWith("[") && trimmed.endsWith("]")) ||
    trimmed === "null" ||
    trimmed === "true" ||
    trimmed === "false" ||
    /^-?\d+(\.\d+)?$/.test(trimmed);

  if (!looksLikeJson) {
    return raw;
  }

  try {
    return JSON.parse(trimmed);
  } catch {
    return raw;
  }
}

export function resetExtensionRegistry() {
  extensionTools.length = 0;
  beforeToolCallHooks.length = 0;
  afterToolCallHooks.length = 0;
  onErrorHooks.length = 0;
  systemPromptPatches.length = 0;
  loadedExtensions.length = 0;
}

export function getExtensionTools(): AgentTool<any>[] {
  return extensionTools.slice();
}

export function getLoadedExtensions(): string[] {
  return loadedExtensions.slice();
}

export function getSystemPromptPatches(): string[] {
  return systemPromptPatches.slice();
}

export function buildRegisteredHooks(): AgentHooks | undefined {
  if (
    beforeToolCallHooks.length === 0 &&
    afterToolCallHooks.length === 0 &&
    onErrorHooks.length === 0
  ) {
    return undefined;
  }

  return {
    beforeToolCall: beforeToolCallHooks.length === 0
      ? undefined
      : async (toolName, args) => {
          for (const hook of beforeToolCallHooks) {
            const result = await hook(toolName, args);
            if (result?.block) {
              return result;
            }
          }
          return undefined;
        },
    afterToolCall: afterToolCallHooks.length === 0
      ? undefined
      : async (toolName, args, result, isError) => {
          for (const hook of afterToolCallHooks) {
            await hook(toolName, args, result, isError);
          }
        },
    onError: onErrorHooks.length === 0
      ? undefined
      : (error, ctx) => {
          for (const hook of onErrorHooks) {
            hook(error, ctx);
          }
        },
  };
}

export function createExtensionApi(context: PieExtensionContext): PieExtensionApi {
  return {
    ...context,
    registerTool(tool) {
      const normalizedTool = {
        ...tool,
        parameters: convertJsonSchemaToTypeBox(tool.parameters),
      };
      extensionTools.push(normalizedTool);
      extensionLog(context, `registered tool: ${tool.name}`);
    },
    registerBeforeToolCall(hook) {
      beforeToolCallHooks.push(hook);
      extensionLog(context, "registered beforeToolCall hook");
    },
    registerAfterToolCall(hook) {
      afterToolCallHooks.push(hook);
      extensionLog(context, "registered afterToolCall hook");
    },
    registerOnError(hook) {
      onErrorHooks.push(hook);
      extensionLog(context, "registered onError hook");
    },
    appendSystemPrompt(text) {
      const trimmed = (text ?? "").trim();
      if (!trimmed) return;
      systemPromptPatches.push(trimmed);
      extensionLog(context, "appended system prompt patch");
    },
    async callHost(name, args) {
      const json = JSON.stringify(args ?? {});
      const raw = (globalThis as any).pieBridge?.callHost?.(name, json);
      return tryParseHostResult(raw) as any;
    },
  };
}

export function registerLoadedExtension(path: string) {
  loadedExtensions.push(path);
}
