import type { AgentTool } from "@pie/agent-core";
import type { Static } from "@sinclair/typebox";
import { Type } from "@sinclair/typebox";
import { resolveToCwd, type PathResolutionOptions } from "@pie/tools-fs";
import { DEFAULT_MAX_BYTES, formatSize, type TruncationResult, truncateHead } from "@pie/tools-fs";

declare const CS: any;
declare const puer: any;

const findSchema = Type.Object({
  pattern: Type.Optional(Type.String({
    description: "The file pattern only, not a shell command. Good inputs: '*.cs', '**/*.json', 'DemoScript.cs', or 'DemoScript'. Do not pass 'find *.cs' as the pattern.",
  })),
  query: Type.Optional(Type.String({ description: "Alias for pattern. You can pass a filename fragment like 'DemoScript'." })),
  name: Type.Optional(Type.String({ description: "Alias for pattern. You can pass a file name like 'DemoScript.cs'." })),
  file_name: Type.Optional(Type.String({ description: "Alias for pattern. You can pass a file name or fragment." })),
  path: Type.Optional(Type.String({ description: "Directory to search in (default: workspace root). Example: 'Scripts' or 'Data'." })),
  limit: Type.Optional(Type.Number({ description: "Maximum number of results (default: 1000)" })),
});

const DEFAULT_LIMIT = 1000;

interface NativeFindResult {
  Results?: string[];
  ScannedDirectories?: number;
  ScannedFiles?: number;
  LimitReached?: boolean;
  Pattern?: string;
  RootPath?: string;
}

export interface NativeFindToolDetails {
  truncation?: TruncationResult;
  resultLimitReached?: number;
  scannedDirectories?: number;
  scannedFiles?: number;
  effectivePattern?: string;
  searchPath?: string;
  rawPattern?: string;
}

function awaitTask<T>(task: any): Promise<T> {
  if (!puer?.$promise) {
    throw new Error("puer.$promise is not available");
  }
  return puer.$promise(task) as Promise<T>;
}

function stripOuterQuotes(value: string): string {
  const trimmed = (value || "").trim();
  if (trimmed.length < 2) {
    return trimmed;
  }

  const first = trimmed[0];
  const last = trimmed[trimmed.length - 1];
  if ((first === "\"" && last === "\"") || (first === "'" && last === "'")) {
    return trimmed.substring(1, trimmed.length - 1).trim();
  }

  return trimmed;
}

function normalizeFindPattern(rawPattern: string): string {
  let pattern = stripOuterQuotes(rawPattern);

  if (pattern.startsWith("find ")) {
    pattern = pattern.substring(5).trim();
  }

  if (pattern.startsWith("-name ")) {
    pattern = pattern.substring(6).trim();
  }

  const nameMatch = pattern.match(/^-name\s+(.+)$/);
  if (nameMatch) {
    pattern = nameMatch[1].trim();
  }

  pattern = stripOuterQuotes(pattern);

  if (pattern.startsWith("./")) {
    pattern = pattern.substring(2);
  }

  return pattern;
}

export function createNativeFindTool(
  cwd: string,
  options?: PathResolutionOptions,
): AgentTool<typeof findSchema> {
  return {
    name: "find",
    label: "find",
    description: `Search for files by filename fragment or glob pattern. Best practice: use a simple filename fragment like 'PlayerController' or a direct filename like 'PlayerController.cs'. Glob examples: '*.cs', '*.json', '**/*.prefab'. Pass only the pattern string, not a shell command. Returns matching paths relative to the search directory. Output is truncated to ${DEFAULT_LIMIT} results or ${DEFAULT_MAX_BYTES / 1024}KB (whichever is hit first).`,
    parameters: findSchema,
    execute: async (
      _toolCallId: string,
      { pattern, query, name, file_name, path: searchDir, limit }: Static<typeof findSchema>,
    ) => {
      const resolvedPattern = pattern || query || name || file_name || "";
      const normalizedPattern = normalizeFindPattern(resolvedPattern);
      if (!normalizedPattern) {
        return {
          content: [{ type: "text" as const, text: "search_files requires a pattern, query, name, or file_name argument." }],
          details: { rawPattern: resolvedPattern, effectivePattern: normalizedPattern },
          isError: true,
        };
      }
      const searchPath = resolveToCwd(searchDir || ".", cwd, options);
      const effectiveLimit = limit ?? DEFAULT_LIMIT;

      if ((globalThis as any).__pieVerboseLogs) {
        (globalThis as any).pieBridge?.log?.("info", `[native find] path=${searchPath} pattern=${normalizedPattern} raw=${resolvedPattern} limit=${effectiveLimit}`);
      }

      const json = await awaitTask<string>(CS.Pie.PieFileBridge.FindAsync(searchPath, normalizedPattern, effectiveLimit));
      const nativeResult = json ? (JSON.parse(json) as NativeFindResult) : {};
      const results = nativeResult.Results ?? [];

      if ((globalThis as any).__pieVerboseLogs) {
        (globalThis as any).pieBridge?.log?.(
          "info",
          `[native find] done path=${searchPath} pattern=${normalizedPattern} matches=${results.length} dirs=${nativeResult.ScannedDirectories ?? 0} files=${nativeResult.ScannedFiles ?? 0}`,
        );
      }

      if (results.length === 0) {
        return {
          content: [{ type: "text" as const, text: "No files found matching pattern" }],
          details: {
            scannedDirectories: nativeResult.ScannedDirectories ?? 0,
            scannedFiles: nativeResult.ScannedFiles ?? 0,
            effectivePattern: nativeResult.Pattern ?? normalizedPattern,
            searchPath: nativeResult.RootPath ?? searchPath,
            rawPattern: resolvedPattern,
          },
          isError: true,
        };
      }

      const rawOutput = results.join("\n");
      const truncation = truncateHead(rawOutput, { maxLines: Number.MAX_SAFE_INTEGER });
      let resultOutput = truncation.content;
      const details: NativeFindToolDetails = {
        scannedDirectories: nativeResult.ScannedDirectories,
        scannedFiles: nativeResult.ScannedFiles,
        effectivePattern: nativeResult.Pattern ?? normalizedPattern,
        searchPath: nativeResult.RootPath ?? searchPath,
        rawPattern: resolvedPattern,
      };
      const notices: string[] = [];

      if (nativeResult.LimitReached) {
        notices.push(`${effectiveLimit} results limit reached`);
        details.resultLimitReached = effectiveLimit;
      }

      if (truncation.truncated) {
        notices.push(`${formatSize(DEFAULT_MAX_BYTES)} limit reached`);
        details.truncation = truncation;
      }

      if (notices.length > 0) {
        resultOutput += `\n\n[${notices.join(". ")}]`;
      }

      return {
        content: [{ type: "text" as const, text: resultOutput }],
        details,
      };
    },
  };
}
